export enum Gender {
  MALE = '男',
  FEMALE = '女'
}

export interface Medication {
  name: string;
  usage: string;  
  amount: string; 
  startDate: string; // 药物起始时间
}

export interface AssessmentRecord {
  id: string;
  date: string;
  scores: {
    emotional: number;
    social: number;
    seizure: number;
    sideEffect: number;
    overall: number;
  };
  totalScore: number;
  notes: string;
}

/**
 * VisitRecord captures a snapshot of clinical state at a specific follow-up point
 */
export interface VisitRecord {
  id: string;
  date: string;
  clinicalSummary: {
    syndrome: string;
    seizureType: string;
    eeg: string;
    mri: string;
    genetic: string;
    other: string;
  };
  medications: Medication[];
  followUpConfig: {
    items: string[];
    intervalMonths: number;
    lastFollowUpDate: string;
    nextFollowUpDate: string;
  };
}

export interface Patient {
  id: string;
  name: string;
  gender: Gender;
  birthday: string; // 出生年月
  age: number;      // 自动生成的年龄
  allergies: string;
  familyHistory: string;
  idCard: string;
  phone: string;
  // 当前最新的临床状态
  clinicalSummary: VisitRecord['clinicalSummary'];
  diagnosis: string;
  diagnosisDate: string;
  medications: Medication[];
  followUpConfig: VisitRecord['followUpConfig'];
  // 历史复诊记录
  visitHistory: VisitRecord[];
  assessmentHistory?: AssessmentRecord[];
  createdAt: number;
}

export interface FollowUpReminder {
  patientId: string;
  patientName: string;
  daysRemaining: number;
  isOverdue: boolean;
  dueDate: string;
}

import React, { useState, useEffect } from 'react';
import { Patient, Gender, Medication, VisitRecord } from '../types';
import { COMMON_MEDICATIONS, FOLLOW_UP_ITEMS } from '../constants';

interface PatientFormProps {
  initialData?: Patient;
  onSubmit: (data: Patient) => void;
  onCancel: () => void;
}

const PatientForm: React.FC<PatientFormProps> = ({ initialData, onSubmit, onCancel }) => {
  const [formData, setFormData] = useState<Partial<Patient>>({
    name: '',
    gender: Gender.MALE,
    birthday: '',
    age: 0,
    allergies: '',
    familyHistory: '',
    idCard: '',
    phone: '',
    clinicalSummary: { 
      syndrome: '', 
      seizureType: '', 
      eeg: '', 
      mri: '', 
      genetic: '', 
      other: '' 
    },
    diagnosis: '',
    diagnosisDate: new Date().toISOString().split('T')[0],
    medications: [{ name: '', usage: '', amount: '', startDate: new Date().toISOString().split('T')[0] }],
    followUpConfig: { 
      items: [], 
      intervalMonths: 3, 
      lastFollowUpDate: new Date().toISOString().split('T')[0], 
      nextFollowUpDate: '' 
    },
    visitHistory: []
  });

  const [otherFollowUpText, setOtherFollowUpText] = useState('');

  useEffect(() => { 
    if (initialData) {
      setFormData(initialData);
      const customItem = initialData.followUpConfig.items.find(item => !FOLLOW_UP_ITEMS.includes(item));
      if (customItem) setOtherFollowUpText(customItem);
    } 
  }, [initialData]);

  // 自动计算年龄
  useEffect(() => {
    if (formData.birthday) {
      const birth = new Date(formData.birthday);
      const today = new Date();
      let age = today.getFullYear() - birth.getFullYear();
      const m = today.getMonth() - birth.getMonth();
      if (m < 0 || (m === 0 && today.getDate() < birth.getDate())) {
        age--;
      }
      setFormData(prev => ({ ...prev, age: Math.max(0, age) }));
    }
  }, [formData.birthday]);

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement | HTMLTextAreaElement>) => {
    const { name, value } = e.target;
    if (name.includes('.')) {
      const [parent, child] = name.split('.');
      setFormData(prev => ({ 
        ...prev, 
        [parent]: { ...(prev[parent as keyof Patient] as any), [child]: value } 
      }));
    } else {
      setFormData(prev => ({ ...prev, [name]: value }));
    }
  };

  const handleMedicationChange = (index: number, field: keyof Medication, value: string) => {
    const newMeds = [...(formData.medications || [])];
    newMeds[index] = { ...newMeds[index], [field]: value };
    setFormData(prev => ({ ...prev, medications: newMeds }));
  };

  const calculateNextDate = () => {
    if (!formData.followUpConfig?.lastFollowUpDate || !formData.followUpConfig?.intervalMonths) return;
    const lastDate = new Date(formData.followUpConfig.lastFollowUpDate);
    lastDate.setMonth(lastDate.getMonth() + Number(formData.followUpConfig.intervalMonths));
    setFormData(prev => ({ 
      ...prev, 
      followUpConfig: { ...prev.followUpConfig!, nextFollowUpDate: lastDate.toISOString().split('T')[0] } 
    }));
  };

  useEffect(() => { calculateNextDate(); }, [formData.followUpConfig?.lastFollowUpDate, formData.followUpConfig?.intervalMonths]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    let finalItems = [...(formData.followUpConfig?.items || [])].filter(i => i !== '其他');
    const predefinedExceptOther = FOLLOW_UP_ITEMS.filter(i => i !== '其他');
    finalItems = finalItems.filter(i => predefinedExceptOther.includes(i));
    if (formData.followUpConfig?.items.includes('其他') && otherFollowUpText.trim()) {
      finalItems.push(otherFollowUpText.trim());
    } else if (formData.followUpConfig?.items.includes('其他')) {
      finalItems.push('其他');
    }

    const currentFollowUpConfig = {
      ...formData.followUpConfig!,
      items: finalItems
    };

    // 自动记录本次就诊历史
    const newVisit: VisitRecord = {
      id: crypto.randomUUID(),
      date: formData.followUpConfig?.lastFollowUpDate || new Date().toISOString().split('T')[0],
      clinicalSummary: { ...formData.clinicalSummary! },
      medications: [...(formData.medications || [])],
      followUpConfig: { ...currentFollowUpConfig }
    };

    const updatedHistory = [...(formData.visitHistory || []), newVisit];

    onSubmit({ 
      ...(formData as Patient), 
      followUpConfig: currentFollowUpConfig,
      visitHistory: updatedHistory,
      id: initialData?.id || crypto.randomUUID(), 
      createdAt: initialData?.createdAt || Date.now() 
    });
  };

  const toggleItem = (item: string) => {
    const items = formData.followUpConfig?.items || [];
    setFormData(prev => ({ 
      ...prev, 
      followUpConfig: { 
        ...prev.followUpConfig!, 
        items: items.includes(item) ? items.filter(i => i !== item) : [...items, item] 
      } 
    }));
  };

  return (
    <form onSubmit={handleSubmit} className="glass rounded-[2.5rem] p-8 space-y-10 animate-fade-in overflow-y-auto max-h-[85vh] shadow-2xl text-gray-900 border-white/40">
      <div className="flex justify-between items-center pb-6 border-b border-white/30">
        <div>
           <h2 className="text-3xl font-black text-gray-900 tracking-tight">
             {initialData ? '更新患儿档案与复诊记录' : '新患儿档案建立'}
           </h2>
           <p className="text-violet-500 text-xs font-black uppercase tracking-[0.2em] mt-1">
             Clinical Follow-up Tracking
           </p>
        </div>
        <button type="button" onClick={onCancel} className="p-3 bg-black/5 hover:bg-black/10 rounded-full transition-colors">
          <svg className="w-6 h-6 text-gray-600" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M6 18L18 6M6 6l12 12"></path></svg>
        </button>
      </div>

      <div className="space-y-12">
        {/* 基本身份信息 */}
        <section>
          <div className="flex items-center gap-2 mb-6 ml-1">
             <div className="w-1.5 h-6 bg-violet-500 rounded-full"></div>
             <h3 className="text-lg font-bold">基本身份信息</h3>
          </div>
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-5 gap-6 bg-white/40 p-8 rounded-[2rem] border border-white/50 shadow-inner">
            <div className="space-y-1.5">
              <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest px-1">患儿姓名</label>
              <input name="name" value={formData.name} onChange={handleInputChange} className="w-full px-5 py-4 bg-white rounded-2xl border-0 ring-1 ring-black/5 focus:ring-4 focus:ring-violet-500/20 outline-none transition-all font-semibold" required />
            </div>
            <div className="space-y-1.5">
              <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest px-1">性别</label>
              <select name="gender" value={formData.gender} onChange={handleInputChange} className="w-full px-5 py-4 bg-white rounded-2xl border-0 ring-1 ring-black/5 outline-none font-semibold">
                <option value={Gender.MALE}>男 (Boy)</option>
                <option value={Gender.FEMALE}>女 (Girl)</option>
              </select>
            </div>
            <div className="space-y-1.5">
              <label className="text-[10px] font-black text-sky-500 uppercase tracking-widest px-1">出生日期</label>
              <input type="date" name="birthday" value={formData.birthday} onChange={handleInputChange} className="w-full px-5 py-4 bg-white rounded-2xl border-0 ring-1 ring-black/5 outline-none font-semibold" required />
            </div>
            <div className="space-y-1.5">
              <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest px-1">计算年龄</label>
              <div className="w-full px-5 py-4 bg-gray-100/50 text-gray-400 rounded-2xl border-0 ring-1 ring-black/5 font-bold">
                {formData.age} 岁
              </div>
            </div>
            <div className="space-y-1.5">
              <label className="text-[10px] font-black text-fuchsia-500 uppercase tracking-widest px-1">过敏史</label>
              <input name="allergies" value={formData.allergies} onChange={handleInputChange} className="w-full px-5 py-4 bg-white rounded-2xl border-0 ring-1 ring-black/5 focus:ring-4 focus:ring-fuchsia-500/20 outline-none transition-all font-semibold" placeholder="药物/食物过敏" />
            </div>
          </div>
        </section>

        {/* 治疗与药物方案 */}
        <section>
          <div className="flex items-center gap-2 mb-6 ml-1">
             <div className="w-1.5 h-6 bg-fuchsia-500 rounded-full"></div>
             <h3 className="text-lg font-bold">治疗与药物起始方案</h3>
          </div>
          <div className="glass-dark p-8 rounded-[2.5rem] border-0">
             <div className="space-y-6">
                {(formData.medications || []).map((med, idx) => {
                  const isKnown = COMMON_MEDICATIONS.includes(med.name);
                  const showManualInput = !isKnown && med.name !== '';

                  return (
                    <div key={idx} className="bg-white/50 p-6 rounded-3xl border border-white/50 space-y-4 shadow-sm relative group">
                      <div className="grid grid-cols-1 lg:grid-cols-12 gap-4 items-end">
                        <div className="lg:col-span-4 space-y-1.5">
                          <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1">ASM 药物名称</label>
                          <select 
                            value={isKnown ? med.name : (med.name === '' ? '' : 'OTHER')}
                            onChange={(e) => {
                              const val = e.target.value;
                              if (val === 'OTHER') handleMedicationChange(idx, 'name', ' '); 
                              else handleMedicationChange(idx, 'name', val);
                            }}
                            className="w-full px-4 py-4 bg-white rounded-xl outline-none text-sm font-bold border-0 ring-1 ring-black/5"
                          >
                            <option value="">选择药物...</option>
                            {COMMON_MEDICATIONS.map(m => <option key={m} value={m}>{m}</option>)}
                            <option value="OTHER">其他...</option>
                          </select>
                          {showManualInput && (
                            <input 
                              autoFocus
                              value={med.name === ' ' ? '' : med.name}
                              onChange={(e) => handleMedicationChange(idx, 'name', e.target.value)}
                              className="w-full px-4 py-4 mt-2 bg-violet-50/50 border-2 border-violet-200 rounded-xl outline-none text-sm font-black text-violet-700"
                              placeholder="输入药名"
                            />
                          )}
                        </div>

                        <div className="lg:col-span-2 space-y-1.5">
                          <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1">用法/用量</label>
                          <input 
                            value={med.usage} 
                            onChange={(e) => handleMedicationChange(idx, 'usage', e.target.value)} 
                            className="w-full px-4 py-4 bg-white rounded-xl outline-none text-sm font-semibold border-0 ring-1 ring-black/5" 
                            placeholder="如: bid 0.25g" 
                          />
                        </div>

                        <div className="lg:col-span-3 space-y-1.5">
                          <label className="text-[10px] font-black text-fuchsia-500 uppercase tracking-widest ml-1">起始用药日期</label>
                          <input 
                            type="date"
                            value={med.startDate} 
                            onChange={(e) => handleMedicationChange(idx, 'startDate', e.target.value)} 
                            className="w-full px-4 py-4 bg-white rounded-xl outline-none text-sm font-semibold border-0 ring-1 ring-black/5" 
                          />
                        </div>

                        <div className="lg:col-span-2 space-y-1.5">
                           <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1">备注</label>
                           <input value={med.amount} onChange={(e) => handleMedicationChange(idx, 'amount', e.target.value)} className="w-full px-4 py-4 bg-white rounded-xl outline-none text-sm font-semibold border-0 ring-1 ring-black/5" placeholder="加药/减药..." />
                        </div>

                        <div className="lg:col-span-1 pb-1 flex justify-center">
                          <button 
                            type="button" 
                            onClick={() => setFormData(p => ({ ...p, medications: p.medications?.filter((_, i) => i !== idx) }))} 
                            className="p-3 bg-fuchsia-50 text-fuchsia-500 rounded-xl hover:bg-fuchsia-500 hover:text-white transition-all"
                          >
                            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16"></path></svg>
                          </button>
                        </div>
                      </div>
                    </div>
                  );
                })}
                <button 
                  type="button" 
                  onClick={() => setFormData(p => ({ ...p, medications: [...(p.medications || []), { name: '', usage: '', amount: '', startDate: new Date().toISOString().split('T')[0] }] }))} 
                  className="w-full py-5 bg-violet-50 text-violet-600 font-black rounded-3xl hover:bg-violet-100 transition-all text-sm border-2 border-dashed border-violet-200"
                >
                  + 添加用药调整记录
                </button>
             </div>
          </div>
        </section>

        {/* 临床概况 */}
        <section>
          <div className="flex items-center gap-2 mb-6 ml-1">
             <div className="w-1.5 h-6 bg-sky-400 rounded-full"></div>
             <h3 className="text-lg font-bold">本次就诊临床评估</h3>
          </div>
          <div className="glass-dark p-8 rounded-[2.5rem] border-0 space-y-8">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div className="space-y-1.5">
                <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">临床诊断</label>
                <input name="diagnosis" value={formData.diagnosis} onChange={handleInputChange} className="w-full px-6 py-5 bg-white/80 border-2 border-sky-400/30 rounded-2xl shadow-sm outline-none font-black text-lg text-sky-700" placeholder="如: 局灶性癫痫" required />
              </div>
              <div className="space-y-1.5">
                <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">癫痫综合征</label>
                <input name="clinicalSummary.syndrome" value={formData.clinicalSummary?.syndrome} onChange={handleInputChange} className="w-full px-6 py-5 bg-white/80 border-2 border-violet-500/30 rounded-2xl shadow-sm outline-none font-black text-lg text-violet-700" placeholder="如: West 综合征" />
              </div>
            </div>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div className="space-y-1.5">
                <label className="text-[10px] font-black text-violet-400 uppercase tracking-widest">脑电图 (EEG)</label>
                <textarea name="clinicalSummary.eeg" value={formData.clinicalSummary?.eeg} onChange={handleInputChange} className="w-full px-5 py-4 bg-white/80 rounded-2xl border-0 ring-1 ring-black/5 outline-none text-sm min-h-[100px]" placeholder="记录本次EEG关键点..." />
              </div>
              <div className="space-y-1.5">
                <label className="text-[10px] font-black text-sky-400 uppercase tracking-widest">头颅影像/MRI</label>
                <textarea name="clinicalSummary.mri" value={formData.clinicalSummary?.mri} onChange={handleInputChange} className="w-full px-5 py-4 bg-white/80 rounded-2xl border-0 ring-1 ring-black/5 outline-none text-sm min-h-[100px]" placeholder="记录影像学变化..." />
              </div>
            </div>
          </div>
        </section>

        {/* 随访管理 */}
        <section className="bg-white/50 p-8 rounded-[2.5rem] border border-white shadow-sm">
           <div className="grid grid-cols-1 lg:grid-cols-2 gap-12">
              <div className="space-y-4">
                 <h3 className="text-xl font-bold mb-4">复诊预约项目</h3>
                 <div className="grid grid-cols-2 sm:grid-cols-3 gap-3">
                   {FOLLOW_UP_ITEMS.map(item => (
                     <div 
                      key={item} 
                      onClick={() => toggleItem(item)} 
                      className={`p-3 rounded-2xl border-2 transition-all cursor-pointer flex items-center justify-center text-center text-[10px] font-black uppercase tracking-widest ${formData.followUpConfig?.items.includes(item) ? 'bg-violet-600 border-violet-600 text-white shadow-lg' : 'bg-white border-black/5 text-gray-400 hover:border-violet-200'}`}
                     >
                       {item}
                     </div>
                   ))}
                </div>
              </div>

              <div className="space-y-8">
                 <div className="grid grid-cols-2 gap-6">
                    <div className="space-y-1.5">
                       <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">随访间隔 (月)</label>
                       <input type="number" name="followUpConfig.intervalMonths" value={formData.followUpConfig?.intervalMonths} onChange={handleInputChange} className="w-full px-5 py-4 bg-white rounded-2xl border-0 ring-1 ring-black/5 outline-none font-bold focus:ring-2 focus:ring-violet-200" />
                    </div>
                    <div className="space-y-1.5">
                       <label className="text-[10px] font-black text-sky-600 uppercase tracking-widest">本次复诊日期</label>
                       <input type="date" name="followUpConfig.lastFollowUpDate" value={formData.followUpConfig?.lastFollowUpDate} onChange={handleInputChange} className="w-full px-5 py-4 bg-white rounded-2xl border-0 ring-1 ring-black/5 outline-none font-bold text-sm" />
                    </div>
                 </div>
                 <div className="p-8 bg-gradient-to-br from-violet-600 to-sky-600 rounded-[2rem] text-white shadow-xl">
                    <span className="text-xs font-black text-violet-100 uppercase tracking-[0.2em] block mb-2">下次预约提醒</span>
                    <span className="text-3xl font-black">{formData.followUpConfig?.nextFollowUpDate || '系统自动生成...'}</span>
                 </div>
              </div>
           </div>
        </section>
      </div>

      <div className="flex gap-6 pt-10 sticky bottom-0 bg-white/30 backdrop-blur-md -mx-8 px-8 pb-4 z-20">
        <button type="submit" className="flex-1 bg-violet-600 text-white font-black py-5 rounded-3xl shadow-2xl hover:bg-violet-700 transition-all text-lg active:scale-95">
          {initialData ? '提交本次复诊' : '初诊建档并保存'}
        </button>
        <button type="button" onClick={onCancel} className="px-12 py-5 bg-white/80 text-gray-700 font-bold rounded-3xl hover:bg-white transition-all text-lg shadow-sm">
          取消
        </button>
      </div>
    </form>
  );
};

export default PatientForm;

import React from 'react';
import { Patient, VisitRecord } from '../types';

interface PatientHistoryProps {
  patient: Patient;
  onBack: () => void;
}

const PatientHistory: React.FC<PatientHistoryProps> = ({ patient, onBack }) => {
  const sortedHistory = [...patient.visitHistory].sort((a, b) => 
    new Date(b.date).getTime() - new Date(a.date).getTime()
  );

  return (
    <div className="max-w-5xl mx-auto space-y-8 animate-fade-in pb-12">
      <div className="flex items-center justify-between">
        <div className="flex items-center gap-4">
          <button onClick={onBack} className="p-3 bg-white/80 rounded-2xl shadow-sm hover:bg-white transition-all">
            <svg className="w-6 h-6 text-gray-600" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M15 19l-7-7 7-7"></path></svg>
          </button>
          <div>
            <h2 className="text-2xl font-black text-gray-900">{patient.name} 的历史诊疗轨迹</h2>
            <p className="text-violet-500 text-xs font-bold uppercase tracking-widest mt-1">
              Clinical Journey · {patient.gender} · {patient.age}岁 · 初诊日期 {patient.diagnosisDate}
            </p>
          </div>
        </div>
      </div>

      {sortedHistory.length > 0 ? (
        <div className="space-y-10 relative before:absolute before:left-8 before:top-4 before:bottom-4 before:w-1 before:bg-white/30 before:rounded-full">
          {sortedHistory.map((visit, index) => (
            <div key={visit.id} className="relative pl-24 group">
              {/* 时间轴标记 */}
              <div className="absolute left-[1.65rem] top-8 w-4 h-4 bg-violet-600 rounded-full border-4 border-white shadow-lg group-hover:scale-125 transition-all"></div>

              <div className="glass rounded-[2rem] p-8 space-y-6 hover:shadow-2xl transition-all border-white/40">
                <div className="flex justify-between items-center pb-4 border-b border-white/20">
                  <div className="flex items-center gap-3">
                    <span className="px-4 py-1.5 bg-violet-600 text-white text-xs font-black rounded-full shadow-md">
                      {visit.date}
                    </span>
                    <span className="text-gray-400 text-xs font-bold">第 {sortedHistory.length - index} 次复诊记录</span>
                  </div>
                  <div className="flex gap-2">
                    {visit.clinicalSummary.syndrome && (
                      <span className="px-3 py-1 bg-sky-50 text-sky-600 text-[10px] font-black rounded-lg border border-sky-100">
                        {visit.clinicalSummary.syndrome}
                      </span>
                    )}
                  </div>
                </div>

                <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
                  <div className="space-y-4">
                    <h4 className="text-[10px] font-black text-gray-400 uppercase tracking-widest">当前用药 ASM</h4>
                    <div className="space-y-2">
                      {visit.medications.map((m, i) => (
                        <div key={i} className="flex justify-between items-center p-3 bg-white/40 rounded-xl border border-white/50">
                          <div>
                            <span className="font-bold text-gray-800">{m.name}</span>
                            <span className="ml-3 text-xs text-gray-500">{m.usage}</span>
                          </div>
                          <div className="text-right">
                             <div className="text-[9px] font-black text-violet-500 uppercase">起始日期</div>
                             <div className="text-xs font-bold">{m.startDate || '未记录'}</div>
                          </div>
                        </div>
                      ))}
                    </div>
                  </div>

                  <div className="space-y-4">
                    <h4 className="text-[10px] font-black text-gray-400 uppercase tracking-widest">检查概况</h4>
                    <div className="space-y-3">
                      <div className="text-sm">
                        <span className="font-bold text-violet-600 mr-2">EEG:</span>
                        <span className="text-gray-600">{visit.clinicalSummary.eeg || '无描述'}</span>
                      </div>
                      <div className="text-sm">
                        <span className="font-bold text-sky-600 mr-2">MRI:</span>
                        <span className="text-gray-600">{visit.clinicalSummary.mri || '无描述'}</span>
                      </div>
                    </div>
                  </div>
                </div>
              </div>
            </div>
          ))}
        </div>
      ) : (
        <div className="glass rounded-[2rem] p-20 text-center">
          <p className="text-gray-400 font-bold">暂无复诊记录存档</p>
        </div>
      )}
    </div>
  );
};

export default PatientHistory;

import React, { useState, useEffect } from 'react';
import Dashboard from './components/Dashboard';
import PatientForm from './components/PatientForm';
import PatientList from './components/PatientList';
import PatientHistory from './components/PatientHistory';
import { storage } from './services/storage';
import { Patient } from './types';

enum View {
  DASHBOARD = 'DASHBOARD',
  LIST = 'LIST',
  FORM = 'FORM',
  HISTORY = 'HISTORY'
}

const App: React.FC = () => {
  const [activeView, setActiveView] = useState<View>(View.DASHBOARD);
  const [patients, setPatients] = useState<Patient[]>([]);
  const [editingPatient, setEditingPatient] = useState<Patient | undefined>(undefined);
  const [historyPatient, setHistoryPatient] = useState<Patient | undefined>(undefined);

  useEffect(() => {
    setPatients(storage.getPatients());
  }, []);

  const handleSavePatient = (patient: Patient) => {
    if (editingPatient) {
      storage.updatePatient(patient);
    } else {
      storage.addPatient(patient);
    }
    setPatients(storage.getPatients());
    setActiveView(View.DASHBOARD);
    setEditingPatient(undefined);
  };

  const handleDeletePatient = (id: string) => {
    if (window.confirm('确认删除该病人记录？此操作无法撤销。')) {
      storage.deletePatient(id);
      setPatients(storage.getPatients());
    }
  };

  const handleDeleteMultiplePatients = (ids: string[]) => {
    if (window.confirm(`确定要永久删除选中的 ${ids.length} 名患者记录吗？`)) {
      const allPatients = storage.getPatients();
      const filtered = allPatients.filter(p => !ids.includes(p.id));
      storage.savePatients(filtered);
      setPatients(filtered);
    }
  };

  const handleEditPatient = (patient: Patient) => {
    setEditingPatient(patient);
    setActiveView(View.FORM);
  };

  const handleViewHistory = (patient: Patient) => {
    setHistoryPatient(patient);
    setActiveView(View.HISTORY);
  };

  return (
    <div className="min-h-screen flex flex-col pb-20 md:pb-0">
      <header className="sticky top-0 z-50 glass border-b-0">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex justify-between h-20 items-center">
            <div className="flex items-center gap-3">
              <div className="w-12 h-12 bg-gradient-to-br from-violet-400 to-violet-600 rounded-2xl flex items-center justify-center text-white font-black italic shadow-lg">
                LZ
              </div>
              <h1 className="text-xl font-bold text-gray-900 tracking-tight hidden sm:block">LZRYEK 癫痫随访</h1>
            </div>

            <nav className="flex space-x-1.5 bg-black/5 p-1.5 rounded-2xl">
              {[
                { id: View.DASHBOARD, label: '概览', icon: 'M4 6h16M4 12h16M4 18h16' },
                { id: View.LIST, label: '查询', icon: 'M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z' },
                { id: View.FORM, label: '建档', icon: 'M12 4v16m8-8H4' },
              ].map(item => (
                <button
                  key={item.id}
                  onClick={() => {
                    setActiveView(item.id);
                    if (item.id !== View.FORM) setEditingPatient(undefined);
                  }}
                  className={`flex items-center gap-2 px-4 py-2 rounded-xl text-sm font-semibold transition-all duration-300 ${
                    (activeView === item.id || (activeView === View.HISTORY && item.id === View.LIST)) 
                    ? 'bg-white shadow-sm text-violet-600' 
                    : 'text-gray-500 hover:text-gray-900'
                  }`}
                >
                  <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d={item.icon}></path>
                  </svg>
                  <span className="hidden md:inline">{item.label}</span>
                </button>
              ))}
            </nav>
          </div>
        </div>
      </header>

      <main className="flex-1 max-w-7xl mx-auto w-full px-4 sm:px-6 lg:px-8 py-8">
        {activeView === View.DASHBOARD && (
          <Dashboard 
            patients={patients} 
            onSelectPatient={handleEditPatient} 
            onAddClick={() => setActiveView(View.FORM)}
          />
        )}

        {activeView === View.LIST && (
          <PatientList 
            patients={patients} 
            onSelect={handleViewHistory} 
            onDelete={handleDeletePatient}
            onDeleteMultiple={handleDeleteMultiplePatients}
          />
        )}

        {activeView === View.FORM && (
          <PatientForm 
            initialData={editingPatient}
            onSubmit={handleSavePatient}
            onCancel={() => {
              setActiveView(View.DASHBOARD);
              setEditingPatient(undefined);
            }}
          />
        )}

        {activeView === View.HISTORY && historyPatient && (
          <PatientHistory 
            patient={historyPatient}
            onBack={() => {
              setActiveView(View.LIST);
              setHistoryPatient(undefined);
            }}
          />
        )}
      </main>

      <footer className="mt-auto py-8 text-center text-gray-600 text-xs px-4">
        <p className="opacity-75">© 2024 LZRYEK Epilepsy Management. <i>By Jefflong</i></p>
      </footer>
    </div>
  );
};

export default App;

