import React, { useState, useEffect } from 'react';
import { Patient, Gender, Medication, VisitRecord } from '../types';
import { COMMON_MEDICATIONS, FOLLOW_UP_ITEMS } from '../constants';

interface PatientFormProps {
  initialData?: Patient;
  onSubmit: (data: Patient) => void;
  onCancel: () => void;
}

const PatientForm: React.FC<PatientFormProps> = ({ initialData, onSubmit, onCancel }) => {
  const [formData, setFormData] = useState<Partial<Patient>>({
    name: '',
    gender: Gender.MALE,
    birthday: '',
    age: 0,
    allergies: '',
    familyHistory: '',
    idCard: '',
    phone: '',
    clinicalSummary: { 
      syndrome: '', 
      seizureType: '', 
      eeg: '', 
      mri: '', 
      genetic: '', 
      biochemical: '',
      other: '' 
    },
    diagnosis: '',
    diagnosisDate: new Date().toISOString().split('T')[0],
    medications: [{ name: '', usage: '', dosage: '', startDate: new Date().toISOString().split('T')[0], endDate: '' }],
    followUpConfig: { 
      items: [], 
      intervalMonths: 3, 
      lastFollowUpDate: new Date().toISOString().split('T')[0], 
      nextFollowUpDate: '' 
    },
    visitHistory: []
  });

  const [otherFollowUpText, setOtherFollowUpText] = useState('');

  useEffect(() => { 
    if (initialData) {
      setFormData(initialData);
      const customItem = initialData.followUpConfig.items.find(item => !FOLLOW_UP_ITEMS.includes(item));
      if (customItem) setOtherFollowUpText(customItem);
    } 
  }, [initialData]);

  useEffect(() => {
    if (formData.birthday) {
      const birth = new Date(formData.birthday);
      const today = new Date();
      let age = today.getFullYear() - birth.getFullYear();
      const m = today.getMonth() - birth.getMonth();
      if (m < 0 || (m === 0 && today.getDate() < birth.getDate())) {
        age--;
      }
      setFormData(prev => ({ ...prev, age: Math.max(0, age) }));
    }
  }, [formData.birthday]);

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement | HTMLTextAreaElement>) => {
    const { name, value } = e.target;
    if (name.includes('.')) {
      const [parent, child] = name.split('.');
      setFormData(prev => ({ 
        ...prev, 
        [parent]: { ...(prev[parent as keyof Patient] as any), [child]: value } 
      }));
    } else {
      setFormData(prev => ({ ...prev, [name]: value }));
    }
  };

  const handleMedicationChange = (index: number, field: keyof Medication, value: string) => {
    const newMeds = [...(formData.medications || [])];
    newMeds[index] = { ...newMeds[index], [field]: value };
    setFormData(prev => ({ ...prev, medications: newMeds }));
  };

  const calculateNextDate = () => {
    if (!formData.followUpConfig?.lastFollowUpDate || !formData.followUpConfig?.intervalMonths) return;
    const lastDate = new Date(formData.followUpConfig.lastFollowUpDate);
    lastDate.setMonth(lastDate.getMonth() + Number(formData.followUpConfig.intervalMonths));
    setFormData(prev => ({ 
      ...prev, 
      followUpConfig: { ...prev.followUpConfig!, nextFollowUpDate: lastDate.toISOString().split('T')[0] } 
    }));
  };

  useEffect(() => { calculateNextDate(); }, [formData.followUpConfig?.lastFollowUpDate, formData.followUpConfig?.intervalMonths]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    let finalItems = [...(formData.followUpConfig?.items || [])].filter(i => i !== '其他');
    const predefinedExceptOther = FOLLOW_UP_ITEMS.filter(i => i !== '其他');
    finalItems = finalItems.filter(i => predefinedExceptOther.includes(i));
    if (formData.followUpConfig?.items.includes('其他') && otherFollowUpText.trim()) {
      finalItems.push(otherFollowUpText.trim());
    }

    const currentFollowUpConfig = { ...formData.followUpConfig!, items: finalItems };

    const newVisit: VisitRecord = {
      id: crypto.randomUUID(),
      date: formData.followUpConfig?.lastFollowUpDate || new Date().toISOString().split('T')[0],
      clinicalSummary: { ...formData.clinicalSummary! },
      medications: [...(formData.medications || [])],
      followUpConfig: { ...currentFollowUpConfig }
    };

    onSubmit({ 
      ...(formData as Patient), 
      followUpConfig: currentFollowUpConfig,
      visitHistory: [...(formData.visitHistory || []), newVisit],
      id: initialData?.id || crypto.randomUUID(), 
      createdAt: initialData?.createdAt || Date.now() 
    });
  };

  const toggleItem = (item: string) => {
    const items = formData.followUpConfig?.items || [];
    setFormData(prev => ({ 
      ...prev, 
      followUpConfig: { 
        ...prev.followUpConfig!, 
        items: items.includes(item) ? items.filter(i => i !== item) : [...items, item] 
      } 
    }));
  };

  return (
    <form onSubmit={handleSubmit} className="glass rounded-[2.5rem] p-8 space-y-10 animate-fade-in overflow-y-auto max-h-[85vh] shadow-2xl text-gray-900 border-white/40">
      <div className="flex justify-between items-center pb-6 border-b border-white/30">
        <div>
           <h2 className="text-3xl font-black text-gray-900 tracking-tight">
             {initialData ? '更新患儿档案与复诊记录' : '新患儿档案建立'}
           </h2>
           <p className="text-violet-500 text-xs font-black uppercase tracking-[0.2em] mt-1">
             Clinical Follow-up Tracking
           </p>
        </div>
        <button type="button" onClick={onCancel} className="p-3 bg-black/5 hover:bg-black/10 rounded-full transition-colors">
          <svg className="w-6 h-6 text-gray-600" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M6 18L18 6M6 6l12 12"></path></svg>
        </button>
      </div>

      <div className="space-y-12">
        {/* 基本身份信息 */}
        <section>
          <div className="flex items-center gap-2 mb-6 ml-1">
             <div className="w-1.5 h-6 bg-violet-500 rounded-full"></div>
             <h3 className="text-lg font-bold">基本身份信息</h3>
          </div>
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6 bg-white/40 p-8 rounded-[2rem] border border-white/50 shadow-inner">
            <div className="space-y-1.5">
              <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest px-1">患儿姓名</label>
              <input name="name" value={formData.name} onChange={handleInputChange} className="w-full px-5 py-4 bg-white rounded-2xl border-0 ring-1 ring-black/5 focus:ring-4 focus:ring-violet-500/20 outline-none transition-all font-semibold" required />
            </div>
            <div className="space-y-1.5">
              <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest px-1">性别</label>
              <select name="gender" value={formData.gender} onChange={handleInputChange} className="w-full px-5 py-4 bg-white rounded-2xl border-0 ring-1 ring-black/5 outline-none font-semibold">
                <option value={Gender.MALE}>男</option>
                <option value={Gender.FEMALE}>女</option>
              </select>
            </div>
            <div className="space-y-1.5">
              <label className="text-[10px] font-black text-sky-500 uppercase tracking-widest px-1">出生日期</label>
              <input type="date" name="birthday" value={formData.birthday} onChange={handleInputChange} className="w-full px-5 py-4 bg-white rounded-2xl border-0 ring-1 ring-black/5 outline-none font-semibold" required />
            </div>
            <div className="space-y-1.5">
              <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest px-1">计算年龄</label>
              <div className="w-full px-5 py-4 bg-gray-100/50 text-gray-400 rounded-2xl border-0 ring-1 ring-black/5 font-bold">
                {formData.age} 岁
              </div>
            </div>
            <div className="md:col-span-2 space-y-1.5">
              <label className="text-[10px] font-black text-fuchsia-500 uppercase tracking-widest px-1">过敏史</label>
              <input name="allergies" value={formData.allergies} onChange={handleInputChange} className="w-full px-5 py-4 bg-white rounded-2xl border-0 ring-1 ring-black/5 outline-none font-semibold" placeholder="药物/食物过敏" />
            </div>
            <div className="md:col-span-2 space-y-1.5">
              <label className="text-[10px] font-black text-violet-500 uppercase tracking-widest px-1">家族史</label>
              <input name="familyHistory" value={formData.familyHistory} onChange={handleInputChange} className="w-full px-5 py-4 bg-white rounded-2xl border-0 ring-1 ring-black/5 outline-none font-semibold" placeholder="家族癫痫或遗传病史" />
            </div>
          </div>
        </section>

        {/* 药物 */}
        <section>
          <div className="flex items-center gap-2 mb-6 ml-1">
             <div className="w-1.5 h-6 bg-fuchsia-500 rounded-full"></div>
             <h3 className="text-lg font-bold">药物</h3>
          </div>
          <div className="glass-dark p-8 rounded-[2.5rem] border-0">
             <div className="space-y-6">
                {(formData.medications || []).map((med, idx) => {
                  const isKnown = COMMON_MEDICATIONS.includes(med.name);
                  return (
                    <div key={idx} className="bg-white/50 p-6 rounded-3xl border border-white/50 space-y-4 shadow-sm relative group transition-all hover:bg-white/70">
                      <div className="grid grid-cols-1 lg:grid-cols-12 gap-4 items-end">
                        <div className="lg:col-span-3 space-y-1.5">
                          <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1">药物名称 (ASM)</label>
                          <select 
                            value={isKnown ? med.name : (med.name === '' ? '' : 'OTHER')}
                            onChange={(e) => {
                              const val = e.target.value;
                              handleMedicationChange(idx, 'name', val === 'OTHER' ? ' ' : val);
                            }}
                            className="w-full px-4 py-3.5 bg-white rounded-xl outline-none text-sm font-bold border-0 ring-1 ring-black/5"
                          >
                            <option value="">选择药物...</option>
                            {COMMON_MEDICATIONS.map(m => <option key={m} value={m}>{m}</option>)}
                            <option value="OTHER">其他...</option>
                          </select>
                          {(!isKnown && med.name !== '') && (
                            <input value={med.name === ' ' ? '' : med.name} onChange={(e) => handleMedicationChange(idx, 'name', e.target.value)} className="w-full px-4 py-3.5 mt-2 bg-violet-50 border-2 border-violet-200 rounded-xl outline-none text-sm font-black" placeholder="输入药名" />
                          )}
                        </div>

                        <div className="lg:col-span-2 space-y-1.5">
                          <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1">用法</label>
                          <input value={med.usage} onChange={(e) => handleMedicationChange(idx, 'usage', e.target.value)} className="w-full px-4 py-3.5 bg-white rounded-xl outline-none text-sm font-semibold border-0 ring-1 ring-black/5" placeholder="如: bid" />
                        </div>

                        <div className="lg:col-span-2 space-y-1.5">
                          <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1">用量</label>
                          <input value={med.dosage} onChange={(e) => handleMedicationChange(idx, 'dosage', e.target.value)} className="w-full px-4 py-3.5 bg-white rounded-xl outline-none text-sm font-semibold border-0 ring-1 ring-black/5" placeholder="如: 0.25g" />
                        </div>

                        <div className="lg:col-span-2 space-y-1.5">
                          <label className="text-[10px] font-black text-violet-500 uppercase tracking-widest ml-1">起始日期</label>
                          <input type="date" value={med.startDate} onChange={(e) => handleMedicationChange(idx, 'startDate', e.target.value)} className="w-full px-4 py-3.5 bg-white rounded-xl outline-none text-sm font-semibold border-0 ring-1 ring-black/5" />
                        </div>

                        <div className="lg:col-span-2 space-y-1.5">
                          <label className="text-[10px] font-black text-fuchsia-500 uppercase tracking-widest ml-1">停药时间 (留空为在治)</label>
                          <input type="date" value={med.endDate || ''} onChange={(e) => handleMedicationChange(idx, 'endDate', e.target.value)} className="w-full px-4 py-3.5 bg-white rounded-xl outline-none text-sm font-semibold border-0 ring-1 ring-black/5" />
                        </div>

                        <div className="lg:col-span-1 pb-1 flex justify-center">
                          <button type="button" onClick={() => setFormData(p => ({ ...p, medications: p.medications?.filter((_, i) => i !== idx) }))} className="p-3 bg-fuchsia-50 text-fuchsia-500 rounded-xl hover:bg-fuchsia-500 hover:text-white transition-all">
                            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16"></path></svg>
                          </button>
                        </div>
                      </div>
                    </div>
                  );
                })}
                <button type="button" onClick={() => setFormData(p => ({ ...p, medications: [...(p.medications || []), { name: '', usage: '', dosage: '', startDate: new Date().toISOString().split('T')[0], endDate: '' }] }))} className="w-full py-4 bg-violet-50 text-violet-600 font-black rounded-2xl hover:bg-violet-100 transition-all text-sm border-2 border-dashed border-violet-200">
                  + 添加药物记录
                </button>
             </div>
          </div>
        </section>

        {/* 临床资料 */}
        <section>
          <div className="flex items-center gap-2 mb-6 ml-1">
             <div className="w-1.5 h-6 bg-sky-400 rounded-full"></div>
             <h3 className="text-lg font-bold">临床资料</h3>
          </div>
          <div className="glass-dark p-8 rounded-[2.5rem] border-0 space-y-8">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
