                <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">临床诊断</label>
                <input name="diagnosis" value={formData.diagnosis} onChange={handleInputChange} className="w-full px-6 py-4 bg-white/80 border-2 border-sky-400/30 rounded-2xl outline-none font-black text-sky-700" placeholder="如: 局灶性癫痫" required />
              </div>
              <div className="space-y-1.5">
                <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">癫痫综合征</label>
                <input name="clinicalSummary.syndrome" value={formData.clinicalSummary?.syndrome} onChange={handleInputChange} className="w-full px-6 py-4 bg-white/80 border-2 border-violet-500/30 rounded-2xl outline-none font-black text-violet-700" placeholder="如: West 综合征" />
              </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
              <div className="space-y-1.5">
                <label className="text-[10px] font-black text-violet-400 uppercase tracking-widest">脑电图 (EEG)</label>
