import { Patient } from '../types';

const STORAGE_KEY = 'LZRYEK_EPILEPSY_PATIENTS';

export const storage = {
  getPatients: (): Patient[] => {
    const data = localStorage.getItem(STORAGE_KEY);
    return data ? JSON.parse(data) : [];
  },

  savePatients: (patients: Patient[]): void => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(patients));
  },

  addPatient: (patient: Patient): void => {
    const patients = storage.getPatients();
    patients.push(patient);
    storage.savePatients(patients);
  },

  updatePatient: (updatedPatient: Patient): void => {
    const patients = storage.getPatients();
    const index = patients.findIndex(p => p.id === updatedPatient.id);
    if (index !== -1) {
      patients[index] = updatedPatient;
      storage.savePatients(patients);
    }
  },

  deletePatient: (id: string): void => {
    const patients = storage.getPatients();
    const filtered = patients.filter(p => p.id !== id);
    storage.savePatients(filtered);
  },

  // 批量合并导入
  importPatients: (newPatients: Patient[]): number => {
    const existing = storage.getPatients();
    const existingIds = new Set(existing.map(p => p.idCard || p.id));

    let addedCount = 0;
    const merged = [...existing];

    newPatients.forEach(np => {
      const identifier = np.idCard || np.id;
      if (!existingIds.has(identifier)) {
        merged.push(np);
        addedCount++;
      }
    });

    storage.savePatients(merged);
    return addedCount;
  }
};

import React, { useRef } from 'react';
import { Patient, FollowUpReminder } from '../types';
import { storage } from '../services/storage';

interface DashboardProps {
  patients: Patient[];
  onSelectPatient: (patient: Patient) => void;
  onAddClick: () => void;
}

const Dashboard: React.FC<DashboardProps> = ({ patients, onSelectPatient, onAddClick }) => {
  const fileInputRef = useRef<HTMLInputElement>(null);

  const getReminders = (): FollowUpReminder[] => {
    const today = new Date();
    return patients
      .map(p => {
        const nextDate = new Date(p.followUpConfig.nextFollowUpDate);
        const diffTime = nextDate.getTime() - today.getTime();
        const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));
        return {
          patientId: p.id,
          patientName: p.name,
          daysRemaining: diffDays,
          isOverdue: diffDays < 0,
          dueDate: p.followUpConfig.nextFollowUpDate
        };
      })
      .filter(r => r.daysRemaining <= 14) 
      .sort((a, b) => a.daysRemaining - b.daysRemaining);
  };

  const reminders = getReminders();

  // 导出 CSV 逻辑
  const exportToCSV = () => {
    if (patients.length === 0) return alert('暂无数据可导出');

    const headers = ['姓名', '性别', '出生日期', '年龄', '过敏史', '家族史', '联系电话', '身份证号', '当前诊断', '当前用药'];
    const rows = patients.map(p => [
      p.name,
      p.gender,
      p.birthday,
      p.age,
      p.allergies,
      p.familyHistory,
      p.phone,
      `'${p.idCard}`, // 加单引号防止Excel长数字截断
      p.diagnosis,
      p.medications.map(m => `${m.name}(${m.usage} ${m.dosage})`).join('; ')
    ]);

    const csvContent = [
      headers.join(','),
      ...rows.map(r => r.map(cell => `"${(cell || '').toString().replace(/"/g, '""')}"`).join(','))
    ].join('\n');

    const blob = new Blob(['\uFEFF' + csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.setAttribute('href', url);
    link.setAttribute('download', `LZRYEK_Patients_Export_${new Date().toISOString().split('T')[0]}.csv`);
    link.click();
  };

  // 导出完整 JSON 备份
  const exportToJSON = () => {
    const dataStr = JSON.stringify(patients, null, 2);
    const blob = new Blob([dataStr], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.setAttribute('href', url);
    link.setAttribute('download', `LZRYEK_Full_Backup_${new Date().toISOString().split('T')[0]}.json`);
    link.click();
  };

  // 导入处理
  const handleImport = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const content = event.target?.result as string;
        if (file.name.endsWith('.json')) {
          const imported = JSON.parse(content);
          const count = storage.importPatients(imported);
          alert(`导入成功！共新增 ${count} 条记录。`);
          window.location.reload();
        } else if (file.name.endsWith('.csv')) {
          // 简单的 CSV 解析（仅针对基本字段）
          alert('CSV 导入功能建议使用 JSON 进行完整迁移。目前的 CSV 导入仅限演示，建议导出 JSON 备份。');
        }
      } catch (err) {
        alert('文件格式错误或解析失败');
      }
    };
    reader.readAsText(file);
  };

  return (
    <div className="grid grid-cols-1 lg:grid-cols-3 gap-8 animate-fade-in">
      <div className="lg:col-span-2 space-y-8">
        <div className="glass rounded-[2rem] p-8 overflow-hidden">
          <div className="flex items-center justify-between mb-8">
            <div>
              <h2 className="text-2xl font-bold text-gray-900 tracking-tight">随访任务清单</h2>
              <p className="text-gray-500 text-sm mt-1">未来 14 天内需要处理的随访</p>
            </div>
            <span className="bg-white/50 backdrop-blur-sm text-gray-700 text-xs font-bold px-4 py-1.5 rounded-full border border-white/50">{reminders.length} 个任务</span>
          </div>

          {reminders.length > 0 ? (
            <div className="space-y-4">
              {reminders.map((reminder) => (
                <div 
                  key={reminder.patientId}
                  onClick={() => {
                    const patient = patients.find(p => p.id === reminder.patientId);
                    if (patient) onSelectPatient(patient);
                  }}
                  className={`flex items-center justify-between p-5 rounded-2xl transition-all active:scale-[0.98] cursor-pointer group glass-dark border-0 hover:bg-white/60`}
                >
                  <div className="flex items-center gap-4">
                    <div className={`w-12 h-12 rounded-2xl flex items-center justify-center font-bold shadow-sm ${reminder.isOverdue ? 'bg-fuchsia-500 text-white' : 'bg-sky-400 text-white'}`}>
                      {reminder.patientName[0]}
                    </div>
                    <div>
                      <h4 className="font-bold text-gray-900 text-lg">{reminder.patientName}</h4>
                      <p className="text-xs text-gray-500 font-medium">随访日期: {reminder.dueDate}</p>
                    </div>
                  </div>
                  <div className="text-right">
                    {reminder.isOverdue ? (
                      <span className="text-fuchsia-600 font-bold bg-fuchsia-100 px-3 py-1 rounded-full text-xs">
                        已逾期 {Math.abs(reminder.daysRemaining)} 天
                      </span>
                    ) : (
                      <span className="text-sky-700 font-bold bg-sky-100 px-3 py-1 rounded-full text-xs">
                        {reminder.daysRemaining === 0 ? '就在今天' : `${reminder.daysRemaining} 天后`}
                      </span>
                    )}
                  </div>
                </div>
              ))}
            </div>
          ) : (
            <div className="text-center py-16 glass-dark rounded-3xl border-0 border-dashed border-white/40">
              <div className="w-16 h-16 bg-white/50 rounded-full flex items-center justify-center mx-auto mb-4">
                 <svg className="w-8 h-8 text-sky-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M5 13l4 4L19 7"></path></svg>
              </div>
              <p className="text-gray-600 font-semibold text-lg">暂无待办</p>
              <p className="text-gray-400 text-sm">随访计划已全部跟进</p>
            </div>
          )}
        </div>
      </div>

      <div className="space-y-8">
        <div className="bg-gradient-to-br from-violet-500 via-fuchsia-400 to-sky-400 p-8 rounded-[2rem] shadow-2xl text-white relative overflow-hidden group">
          <div className="absolute top-0 right-0 -mr-16 -mt-16 w-48 h-48 bg-white/10 rounded-full blur-3xl group-hover:bg-white/20 transition-all"></div>
          <h3 className="text-xl font-bold mb-6 flex items-center gap-2">
             <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M12 4v16m8-8H4"></path></svg>
             核心操作
          </h3>
          <div className="space-y-4">
            <button 
              onClick={onAddClick}
              className="w-full bg-white text-violet-600 font-bold py-4 px-4 rounded-2xl shadow-xl flex items-center justify-center gap-2 hover:bg-white/90 transition-all active:scale-95"
            >
              新病人建档
            </button>

            <div className="pt-4 border-t border-white/20 space-y-3">
              <p className="text-xs font-black uppercase tracking-widest opacity-80">数据管理</p>
              <div className="grid grid-cols-2 gap-3">
                <button 
                  onClick={exportToCSV}
