import React, { useState, useEffect } from 'react';
import { Patient, Gender, Medication, VisitRecord } from '../types';
import { COMMON_MEDICATIONS, FOLLOW_UP_ITEMS } from '../constants';

interface PatientFormProps {
  initialData?: Patient;
  onSubmit: (data: Patient) => void;
  onCancel: () => void;
}

const PatientForm: React.FC<PatientFormProps> = ({ initialData, onSubmit, onCancel }) => {
  const [formData, setFormData] = useState<Partial<Patient>>({
    name: '', gender: Gender.MALE, birthday: '', age: 0, allergies: '', familyHistory: '', idCard: '', phone: '',
    clinicalSummary: { syndrome: '', seizureType: '', eeg: '', mri: '', genetic: '', biochemical: '', other: '' },
    diagnosis: '', diagnosisDate: new Date().toISOString().split('T')[0],
    medications: [{ name: '', usage: '', dosage: '', startDate: new Date().toISOString().split('T')[0], endDate: '' }],
    followUpConfig: { items: [], intervalMonths: 3, lastFollowUpDate: new Date().toISOString().split('T')[0], nextFollowUpDate: '' },
    visitHistory: []
  });

  const [otherFollowUpText, setOtherFollowUpText] = useState('');

  useEffect(() => { 
    if (initialData) {
      setFormData(initialData);
      const customItem = initialData.followUpConfig.items.find(item => !FOLLOW_UP_ITEMS.includes(item));
      if (customItem) setOtherFollowUpText(customItem);
    } 
  }, [initialData]);

  useEffect(() => {
    if (formData.birthday) {
      const birth = new Date(formData.birthday);
      const today = new Date();
      let age = today.getFullYear() - birth.getFullYear();
      const m = today.getMonth() - birth.getMonth();
      if (m < 0 || (m === 0 && today.getDate() < birth.getDate())) age--;
      setFormData(prev => ({ ...prev, age: Math.max(0, age) }));
    }
  }, [formData.birthday]);

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement | HTMLTextAreaElement>) => {
    const { name, value } = e.target;
    if (name.includes('.')) {
      const [parent, child] = name.split('.');
      setFormData(prev => ({ ...prev, [parent]: { ...(prev[parent as keyof Patient] as any), [child]: value } }));
    } else {
      setFormData(prev => ({ ...prev, [name]: value }));
    }
  };

  const handleMedicationChange = (index: number, field: keyof Medication, value: string) => {
    const newMeds = [...(formData.medications || [])];
    newMeds[index] = { ...newMeds[index], [field]: value };
    setFormData(prev => ({ ...prev, medications: newMeds }));
  };

  const calculateNextDate = () => {
    if (!formData.followUpConfig?.lastFollowUpDate || !formData.followUpConfig?.intervalMonths) return;
    const lastDate = new Date(formData.followUpConfig.lastFollowUpDate);
    lastDate.setMonth(lastDate.getMonth() + Number(formData.followUpConfig.intervalMonths));
    setFormData(prev => ({ ...prev, followUpConfig: { ...prev.followUpConfig!, nextFollowUpDate: lastDate.toISOString().split('T')[0] } }));
  };

  useEffect(() => { calculateNextDate(); }, [formData.followUpConfig?.lastFollowUpDate, formData.followUpConfig?.intervalMonths]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    let finalItems = [...(formData.followUpConfig?.items || [])].filter(i => i !== '其他');
    if (formData.followUpConfig?.items.includes('其他') && otherFollowUpText.trim()) finalItems.push(otherFollowUpText.trim());
    const currentFollowUpConfig = { ...formData.followUpConfig!, items: finalItems };
    const newVisit: VisitRecord = {
      id: crypto.randomUUID(), date: formData.followUpConfig?.lastFollowUpDate || new Date().toISOString().split('T')[0],
      clinicalSummary: { ...formData.clinicalSummary! }, medications: [...(formData.medications || [])], followUpConfig: { ...currentFollowUpConfig }
    };
    onSubmit({ ...(formData as Patient), followUpConfig: currentFollowUpConfig, visitHistory: [...(formData.visitHistory || []), newVisit], id: initialData?.id || crypto.randomUUID(), createdAt: initialData?.createdAt || Date.now() });
  };

  const toggleItem = (item: string) => {
    const items = formData.followUpConfig?.items || [];
    setFormData(prev => ({ ...prev, followUpConfig: { ...prev.followUpConfig!, items: items.includes(item) ? items.filter(i => i !== item) : [...items, item] } }));
  };

  return (
    <form onSubmit={handleSubmit} className="glass rounded-[3rem] p-10 space-y-12 animate-fade-in overflow-y-auto max-h-[85vh] shadow-2xl border-white/40">
      <div className="flex justify-between items-center pb-8 border-b-2 border-black/10">
        <div>
           <h2 className="text-5xl font-black text-black tracking-tighter">
             {initialData ? '更新患儿随访档案' : '新建患儿诊疗档案'}
           </h2>
           <p className="text-black text-xl font-bold mt-2 uppercase tracking-widest opacity-60">Clinical Follow-up Management</p>
        </div>
        <button type="button" onClick={onCancel} className="p-4 bg-black/5 hover:bg-black/10 rounded-full transition-colors">
          <svg className="w-8 h-8 text-black" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M6 18L18 6M6 6l12 12"></path></svg>
        </button>
      </div>

      <div className="space-y-16">
        <section>
          <div className="flex items-center gap-3 mb-8 ml-1">
             <div className="w-2.5 h-10 bg-black rounded-full"></div>
             <h3 className="text-3xl font-black text-black">基本身份信息</h3>
          </div>
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-8 bg-white/50 p-10 rounded-[2.5rem] border-2 border-black/5">
            <div className="space-y-2">
              <label className="text-base font-black text-black uppercase tracking-widest px-1">患儿姓名</label>
              <input name="name" value={formData.name} onChange={handleInputChange} className="w-full px-6 py-5 bg-white rounded-2xl border-2 border-black/10 focus:border-black outline-none font-black text-xl" required />
            </div>
            <div className="space-y-2">
              <label className="text-base font-black text-black uppercase tracking-widest px-1">性别</label>
              <select name="gender" value={formData.gender} onChange={handleInputChange} className="w-full px-6 py-5 bg-white rounded-2xl border-2 border-black/10 outline-none font-black text-xl">
                <option value={Gender.MALE}>男</option>
                <option value={Gender.FEMALE}>女</option>
              </select>
            </div>
            <div className="space-y-2">
              <label className="text-base font-black text-black uppercase tracking-widest px-1">出生日期</label>
              <input type="date" name="birthday" value={formData.birthday} onChange={handleInputChange} className="w-full px-6 py-5 bg-white rounded-2xl border-2 border-black/10 outline-none font-black text-xl" required />
            </div>
            <div className="space-y-2">
              <label className="text-base font-black text-black uppercase tracking-widest px-1">计算年龄</label>
              <div className="w-full px-6 py-5 bg-black/5 text-black rounded-2xl font-black text-xl">{formData.age} 岁</div>
            </div>
            <div className="md:col-span-2 space-y-2">
              <label className="text-base font-black text-black uppercase tracking-widest px-1">过敏史</label>
              <input name="allergies" value={formData.allergies} onChange={handleInputChange} className="w-full px-6 py-5 bg-white rounded-2xl border-2 border-black/10 outline-none font-black text-xl" placeholder="药物/食物过敏情况" />
            </div>
            <div className="md:col-span-2 space-y-2">
              <label className="text-base font-black text-black uppercase tracking-widest px-1">家族史</label>
              <input name="familyHistory" value={formData.familyHistory} onChange={handleInputChange} className="w-full px-6 py-5 bg-white rounded-2xl border-2 border-black/10 outline-none font-black text-xl" placeholder="家族癫痫或遗传病史" />
            </div>
          </div>
        </section>

        <section>
          <div className="flex items-center gap-3 mb-8 ml-1">
             <div className="w-2.5 h-10 bg-black rounded-full"></div>
             <h3 className="text-3xl font-black text-black">药物管理 (ASM)</h3>
          </div>
          <div className="space-y-8">
            {(formData.medications || []).map((med, idx) => (
              <div key={idx} className="bg-white/70 p-10 rounded-[2.5rem] border-2 border-black/10 space-y-6 shadow-sm">
                <div className="grid grid-cols-1 lg:grid-cols-12 gap-8 items-end">
                  <div className="lg:col-span-3 space-y-2">
                    <label className="text-base font-black text-black uppercase tracking-widest ml-1">药物名称</label>
                    <select value={COMMON_MEDICATIONS.includes(med.name) ? med.name : (med.name === '' ? '' : 'OTHER')} onChange={(e) => handleMedicationChange(idx, 'name', e.target.value === 'OTHER' ? ' ' : e.target.value)} className="w-full px-5 py-5 bg-white rounded-2xl border-2 border-black/10 font-black text-lg outline-none">
                      <option value="">选择药物...</option>
                      {COMMON_MEDICATIONS.map(m => <option key={m} value={m}>{m}</option>)}
                      <option value="OTHER">其他药物</option>
                    </select>
                    {(!COMMON_MEDICATIONS.includes(med.name) && med.name !== '') && (
                      <input value={med.name === ' ' ? '' : med.name} onChange={(e) => handleMedicationChange(idx, 'name', e.target.value)} className="w-full px-5 py-5 mt-4 bg-sky-50 border-2 border-sky-200 rounded-2xl font-black text-lg outline-none" placeholder="手动输入药名" />
                    )}
                  </div>
                  <div className="lg:col-span-2 space-y-2">
                    <label className="text-base font-black text-black uppercase tracking-widest ml-1">用法</label>
                    <input value={med.usage} onChange={(e) => handleMedicationChange(idx, 'usage', e.target.value)} className="w-full px-5 py-5 bg-white rounded-2xl border-2 border-black/10 font-black text-lg outline-none" placeholder="如: bid" />
