                    <label className="text-base font-black text-black uppercase tracking-widest ml-1">用量</label>
                    <input value={med.dosage} onChange={(e) => handleMedicationChange(idx, 'dosage', e.target.value)} className="w-full px-5 py-5 bg-white rounded-2xl border-2 border-black/10 font-black text-lg outline-none" placeholder="如: 0.25g" />
