                    <input type="date" value={med.endDate || ''} onChange={(e) => handleMedicationChange(idx, 'endDate', e.target.value)} className="w-full px-5 py-5 bg-white rounded-2xl border-2 border-black/10 font-black text-lg outline-none" />
                  </div>
                  <div className="lg:col-span-1 pb-1">
                    <button type="button" onClick={() => setFormData(p => ({ ...p, medications: p.medications?.filter((_, i) => i !== idx) }))} className="p-5 bg-black text-white rounded-2xl hover:bg-red-600 transition-all shadow-lg">
                      <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16"></path></svg>
