import React, { useState, useMemo } from 'react';
import { Patient, Gender } from '../types';

interface PatientListProps {
  patients: Patient[];
  onSelect: (patient: Patient) => void;
  onDelete: (id: string) => void;
  onDeleteMultiple: (ids: string[]) => void;
}

const PatientList: React.FC<PatientListProps> = ({ patients, onSelect, onDelete, onDeleteMultiple }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [startDate, setStartDate] = useState('');
  const [endDate, setEndDate] = useState('');
  const [selectedIds, setSelectedIds] = useState<string[]>([]);
  const [showInsights, setShowInsights] = useState(false);

  const filteredPatients = useMemo(() => {
    return patients.filter(p => {
      const searchLower = searchTerm.toLowerCase();
      const matchesSearch = p.name.toLowerCase().includes(searchLower) || p.idCard.includes(searchTerm) || p.phone.includes(searchTerm) || p.diagnosis.toLowerCase().includes(searchLower) || (p.clinicalSummary?.syndrome || '').toLowerCase().includes(searchLower) || p.medications.some(m => m.name.toLowerCase().includes(searchLower));
      const patientDate = new Date(p.createdAt).toISOString().split('T')[0];
      const matchesStart = !startDate || patientDate >= startDate;
      const matchesEnd = !endDate || patientDate <= endDate;
      return matchesSearch && matchesStart && matchesEnd;
    });
  }, [patients, searchTerm, startDate, endDate]);

  const stats = useMemo(() => {
    const total = filteredPatients.length;
    if (total === 0) return null;
    const genderCount = { male: 0, female: 0 };
    const ageGroups = { infant: 0, toddler: 0, preschool: 0, school: 0, adolescent: 0 };
    const medUsage: Record<string, number> = {};
    filteredPatients.forEach(p => {
      if (p.gender === Gender.MALE) genderCount.male++; else genderCount.female++;
      if (p.age <= 1) ageGroups.infant++; else if (p.age <= 3) ageGroups.toddler++; else if (p.age <= 6) ageGroups.preschool++; else if (p.age <= 12) ageGroups.school++; else ageGroups.adolescent++;
      p.medications.forEach(m => { const name = m.name.split(' ')[0].trim(); if (name) medUsage[name] = (medUsage[name] || 0) + 1; });
    });
    const topMeds = Object.entries(medUsage).sort((a, b) => b[1] - a[1]).slice(0, 5);
    return { total, genderCount, ageGroups, topMeds };
  }, [filteredPatients]);

  return (
    <div className="space-y-10 animate-fade-in pb-32">
      <div className="glass rounded-[3rem] p-10 shadow-2xl border-white/40 space-y-10">
        <div className="flex flex-col lg:flex-row justify-between items-start lg:items-center gap-8">
          <div className="flex items-center gap-6">
            <div className="w-20 h-20 bg-black rounded-3xl flex items-center justify-center text-white shadow-2xl">
              <svg className="w-10 h-10" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z"></path></svg>
            </div>
            <div>
              <h2 className="text-4xl font-black text-black tracking-tight">智能档案查询</h2>
              <p className="text-black text-lg font-bold uppercase tracking-widest opacity-60 mt-1">Pediatric Database Search</p>
            </div>
          </div>

          <div className="flex items-center bg-black/5 p-2 rounded-3xl border border-black/10">
             <button onClick={() => setShowInsights(false)} className={`px-10 py-4 rounded-2xl text-base font-black transition-all ${!showInsights ? 'bg-black text-white shadow-xl' : 'text-black opacity-40 hover:opacity-100'}`}>档案列表</button>
             <button onClick={() => setShowInsights(true)} className={`px-10 py-4 rounded-2xl text-base font-black transition-all ${showInsights ? 'bg-black text-white shadow-xl' : 'text-black opacity-40 hover:opacity-100'}`}>分布统计</button>
          </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-12 gap-6">
          <div className="relative group lg:col-span-6">
            <input type="text" placeholder="搜索患儿姓名、药物、临床表现..." value={searchTerm} onChange={(e) => setSearchTerm(e.target.value)} className="w-full pl-16 pr-6 py-6 bg-white rounded-3xl border-4 border-black/5 focus:border-black outline-none transition-all font-black text-2xl text-black shadow-inner" />
            <svg className="w-8 h-8 text-black absolute left-5 top-[1.3rem]" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z"></path></svg>
          </div>
          <div className="lg:col-span-4 flex gap-4">
             <div className="flex-1 relative">
                <span className="absolute left-5 top-2 text-[10px] font-black text-black uppercase opacity-40">From</span>
                <input type="date" value={startDate} onChange={(e) => setStartDate(e.target.value)} className="w-full px-5 pt-8 pb-3 bg-white rounded-2xl border-2 border-black/5 font-black text-lg text-black outline-none" />
             </div>
             <div className="flex-1 relative">
                <span className="absolute left-5 top-2 text-[10px] font-black text-black uppercase opacity-40">To</span>
                <input type="date" value={endDate} onChange={(e) => setEndDate(e.target.value)} className="w-full px-5 pt-8 pb-3 bg-white rounded-2xl border-2 border-black/5 font-black text-lg text-black outline-none" />
             </div>
          </div>
          <button onClick={() => {setSearchTerm(''); setStartDate(''); setEndDate('');}} className="lg:col-span-2 py-6 bg-black text-white rounded-3xl font-black text-lg hover:opacity-80 transition active:scale-95">重置筛选</button>
        </div>
      </div>

      {showInsights && stats ? (
        <div className="grid grid-cols-1 md:grid-cols-3 gap-10 animate-fade-in">
          <div className="glass rounded-[3rem] p-10 flex flex-col items-center justify-center space-y-8 shadow-xl border-black/5">
            <h3 className="text-xl font-black text-black uppercase tracking-widest">患儿性别占比</h3>
            <div className="relative w-56 h-56">
               <svg className="w-full h-full transform -rotate-90"><circle cx="112" cy="112" r="90" fill="transparent" stroke="#E5E7EB" strokeWidth="24" /><circle cx="112" cy="112" r="90" fill="transparent" stroke="#000000" strokeWidth="24" strokeDasharray={565} strokeDashoffset={565 * (1 - stats.genderCount.male / stats.total)} /></svg>
               <div className="absolute inset-0 flex flex-col items-center justify-center">
                  <span className="text-5xl font-black text-black">{Math.round((stats.genderCount.male / stats.total) * 100)}%</span>
