                { label: '学龄前(3-6)', count: stats.ageGroups.preschool },
                { label: '学龄(6-12)', count: stats.ageGroups.school },
                { label: '青春(12-18+)', count: stats.ageGroups.adolescent },
              ].map((item, i) => (
                <div key={i} className="space-y-2">
                   <div className="flex justify-between text-base font-black"><span className="text-black opacity-60">{item.label}</span><span className="text-black">{item.count}人</span></div>
                   <div className="w-full h-4 bg-black/5 rounded-full overflow-hidden"><div className="h-full bg-black" style={{ width: `${(item.count / stats.total) * 100}%` }}></div></div>
