import React, { useState } from 'react';
import { Patient, AssessmentRecord } from '../types';
import { storage } from '../services/storage';

interface AssessmentToolProps {
  patients: Patient[];
  onSaved: () => void;
}

const AssessmentTool: React.FC<AssessmentToolProps> = ({ patients, onSaved }) => {
  const [selectedPatientId, setSelectedPatientId] = useState<string>('');
  const [scores, setScores] = useState({ emotional: 5, social: 5, seizure: 5, sideEffect: 5, overall: 5 });
  const [notes, setNotes] = useState('');

  const calculateTotal = () => {
    const sum = scores.emotional + scores.social + scores.seizure + (10 - scores.sideEffect) + scores.overall;
    return (sum / 50) * 100;
  };

  const handleSave = () => {
    if (!selectedPatientId) return alert('请先选择待评估患儿');
    const patient = patients.find(p => p.id === selectedPatientId);
    if (!patient) return;
    const newRecord: AssessmentRecord = { id: crypto.randomUUID(), date: new Date().toISOString().split('T')[0], scores: { ...scores }, totalScore: Math.round(calculateTotal()), notes };
    storage.updatePatient({ ...patient, assessmentHistory: [...(patient.assessmentHistory || []), newRecord] });
    onSaved();
  };

  const currentScore = calculateTotal();

  return (
    <div className="max-w-5xl mx-auto space-y-12 animate-fade-in pb-20">
      <div className="glass rounded-[4rem] p-12 shadow-2xl border-white/40">
        <h2 className="text-5xl font-black text-black mb-12 flex items-center gap-5 tracking-tighter">
           <div className="w-20 h-20 bg-black rounded-3xl flex items-center justify-center text-white shadow-2xl"><svg className="w-10 h-10" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M9 19v-6a2 2 0 00-2-2H5a2 2 0 00-2 2v6a2 2 0 002 2h2a2 2 0 002-2zm0 0V9a2 2 0 012-2h2a2 2 0 012 2v10m-6 0a2 2 0 002 2h2a2 2 0 002-2m0 0V5a2 2 0 012-2h2a2 2 0 012 2v14a2 2 0 01-2 2h-2a2 2 0 01-2-2z"></path></svg></div>
           QOLIE 生活质量临床测评
        </h2>

        <div className="space-y-16">
          <div className="space-y-5">
             <label className="text-lg font-black text-black uppercase tracking-[0.3em] opacity-40 ml-2">测评对象 (患儿档案)</label>
             <select value={selectedPatientId} onChange={(e) => setSelectedPatientId(e.target.value)} className="w-full px-10 py-8 bg-white/80 border-4 border-black/10 rounded-[2rem] font-black text-3xl text-black outline-none focus:border-black shadow-inner appearance-none transition-all">
               <option value="">点击此处从档案库选择患儿...</option>
               {patients.map(p => ( <option key={p.id} value={p.id}>{p.name} · {p.gender} · {p.age}岁</option> ))}
             </select>
          </div>

          <div className="grid grid-cols-1 lg:grid-cols-2 gap-20">
            <div className="space-y-12">
               {[
                 { key: 'emotional', label: '情绪平衡', desc: '焦虑、沮丧或易怒程度' },
                 { key: 'social', label: '社会适应', desc: '学习、社交及家庭生活' },
                 { key: 'seizure', label: '发作恐惧', desc: '对下次发作的心理负担' },
                 { key: 'sideEffect', label: '药物副作用', desc: '对认知、精力的物理干扰' },
                 { key: 'overall', label: '整体质量', desc: '综合主观生活水平评价' },
               ].map((item) => (
                 <div key={item.key} className="space-y-5">
                   <div className="flex justify-between items-end"><div className="space-y-1"><h4 className="text-2xl font-black text-black">{item.label}</h4><p className="text-base text-black opacity-40 font-bold">{item.desc}</p></div><span className="text-5xl font-black text-black">{scores[item.key as keyof typeof scores]}</span></div>
                   <input type="range" min="0" max="10" value={scores[item.key as keyof typeof scores]} onChange={(e) => setScores(p => ({ ...p, [item.key]: parseInt(e.target.value) }))} className="w-full h-4 bg-black/10 rounded-full appearance-none cursor-pointer accent-black" />
                 </div>
               ))}
            </div>

            <div className="flex flex-col items-center justify-center space-y-10 bg-black/5 rounded-[3.5rem] p-12 border-4 border-white shadow-2xl">
               <div className="relative flex items-center justify-center">
                  <svg className="w-64 h-64 transform -rotate-90"><circle cx="128" cy="128" r="110" stroke="#000000" strokeWidth="20" fill="transparent" className="opacity-5" /><circle cx="128" cy="128" r="110" stroke="#000000" strokeWidth="20" fill="transparent" strokeDasharray={690} strokeDashoffset={690 * (1 - currentScore / 100)} className="transition-all duration-1000 ease-out" /></svg>
                  <div className="absolute flex flex-col items-center">
                     <span className="text-7xl font-black tracking-tighter text-black">{Math.round(currentScore)}</span>
                     <span className="text-sm font-black text-black opacity-40 uppercase tracking-widest mt-2">QOL 指数</span>
                  </div>
               </div>
               <div className="w-full space-y-4">
                  <label className="text-base font-black text-black uppercase tracking-widest opacity-40 ml-2">测评观察备注</label>
                  <textarea value={notes} onChange={(e) => setNotes(e.target.value)} placeholder="记录测评期间的临床观察细节..." className="w-full px-8 py-6 bg-white rounded-3xl border-2 border-black/10 outline-none font-bold text-xl min-h-[180px] text-black" />
               </div>
            </div>
          </div>

          <div className="flex gap-8 pt-6">
             <button onClick={handleSave} className="flex-1 bg-black text-white font-black py-8 rounded-[2.5rem] shadow-2xl hover:opacity-90 transition-all active:scale-95 text-3xl">保存测评档案</button>
             <button onClick={() => window.history.back()} className="px-16 py-8 bg-white text-black font-black border-4 border-black rounded-[2.5rem] text-3xl hover:bg-gray-50 transition-all">取消测评</button>
          </div>
        </div>
      </div>
    </div>
  );
};

