             <div className="w-1.5 h-6 bg-sky-400 rounded-full"></div>
             <h3 className="text-lg font-bold">临床资料</h3>
          </div>
          <div className="glass-dark p-8 rounded-[2.5rem] border-0 space-y-8">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div className="space-y-1.5">
                <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">临床诊断</label>
                <input name="diagnosis" value={formData.diagnosis} onChange={handleInputChange} className="w-full px-6 py-4 bg-white/80 border-2 border-sky-400/30 rounded-2xl outline-none font-black text-sky-700" placeholder="如: 局灶性癫痫" required />
              </div>
