                 <h3 className="text-xl font-bold mb-4">复诊预约项目</h3>
                 <div className="grid grid-cols-2 sm:grid-cols-3 gap-3">
                   {FOLLOW_UP_ITEMS.map(item => (
                     <div key={item} onClick={() => toggleItem(item)} className={`p-3 rounded-2xl border-2 transition-all cursor-pointer flex items-center justify-center text-center text-[10px] font-black uppercase tracking-widest ${formData.followUpConfig?.items.includes(item) ? 'bg-violet-600 border-violet-600 text-white shadow-lg' : 'bg-white border-black/5 text-gray-400 hover:border-violet-200'}`}>
                       {item}
                     </div>
                   ))}
                </div>
              </div>
              <div className="space-y-8">
                 <div className="grid grid-cols-2 gap-6">
                    <div className="space-y-1.5">
                       <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">随访间隔 (月)</label>
                       <input type="number" name="followUpConfig.intervalMonths" value={formData.followUpConfig?.intervalMonths} onChange={handleInputChange} className="w-full px-5 py-4 bg-white rounded-2xl border-0 ring-1 ring-black/5 outline-none font-bold" />
                    </div>
