                 </div>
                 <div className="p-8 bg-gradient-to-br from-violet-600 to-sky-600 rounded-[2rem] text-white shadow-xl">
                    <span className="text-xs font-black text-violet-100 uppercase tracking-[0.2em] block mb-2">下次预约提醒</span>
                    <span className="text-3xl font-black">{formData.followUpConfig?.nextFollowUpDate || '...'}</span>
                 </div>
              </div>
           </div>
        </section>
      </div>

      <div className="flex gap-6 pt-10 sticky bottom-0 bg-white/30 backdrop-blur-md -mx-8 px-8 pb-4 z-20">
        <button type="submit" className="flex-1 bg-violet-600 text-white font-black py-5 rounded-3xl shadow-2xl hover:bg-violet-700 transition-all text-lg active:scale-95">
          {isNewVisit ? '完成并生成就诊记录' : (initialData ? '保存档案修改' : '确认建档')}
        </button>
        <button type="button" onClick={onCancel} className="px-12 py-5 bg-white/80 text-gray-700 font-bold rounded-3xl hover:bg-white transition-all text-lg shadow-sm">
          取消
        </button>
      </div>
    </form>
  );
};

export default PatientForm;

import React, { useState, useMemo } from 'react';
import { Patient, Gender } from '../types';

interface PatientListProps {
  patients: Patient[];
  onSelect: (patient: Patient) => void; // 查看历史
  onNewVisit: (patient: Patient) => void; // 新就诊
  onEdit: (patient: Patient) => void; // 修改资料
  onDelete: (id: string) => void;
  onDeleteMultiple: (ids: string[]) => void;
}

const PatientList: React.FC<PatientListProps> = ({ patients, onSelect, onNewVisit, onEdit, onDelete, onDeleteMultiple }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [startDate, setStartDate] = useState('');
  const [endDate, setEndDate] = useState('');
  const [showInsights, setShowInsights] = useState(false);

  const filteredPatients = useMemo(() => {
    return patients.filter(p => {
      const searchLower = searchTerm.toLowerCase();
      const matchesSearch = p.name.toLowerCase().includes(searchLower) || p.idCard.includes(searchTerm) || p.phone.includes(searchTerm) || p.diagnosis.toLowerCase().includes(searchLower) || (p.clinicalSummary?.syndrome || '').toLowerCase().includes(searchLower) || p.medications.some(m => m.name.toLowerCase().includes(searchLower));
      const patientDate = new Date(p.createdAt).toISOString().split('T')[0];
      const matchesStart = !startDate || patientDate >= startDate;
      const matchesEnd = !endDate || patientDate <= endDate;
      return matchesSearch && matchesStart && matchesEnd;
    });
  }, [patients, searchTerm, startDate, endDate]);

  const stats = useMemo(() => {
    const total = filteredPatients.length;
    if (total === 0) return null;
    const genderCount = { male: 0, female: 0 };
    const ageGroups = { infant: 0, toddler: 0, preschool: 0, school: 0, adolescent: 0 };
    const medUsage: Record<string, number> = {};
    filteredPatients.forEach(p => {
      if (p.gender === Gender.MALE) genderCount.male++; else genderCount.female++;
      if (p.age <= 1) ageGroups.infant++; else if (p.age <= 3) ageGroups.toddler++; else if (p.age <= 6) ageGroups.preschool++; else if (p.age <= 12) ageGroups.school++; else ageGroups.adolescent++;
      p.medications.forEach(m => { const name = m.name.split(' ')[0].trim(); if (name) medUsage[name] = (medUsage[name] || 0) + 1; });
    });
    const topMeds = Object.entries(medUsage).sort((a, b) => b[1] - a[1]).slice(0, 5);
    return { total, genderCount, ageGroups, topMeds };
  }, [filteredPatients]);

  return (
    <div className="space-y-8 animate-fade-in pb-20">
      <div className="glass rounded-[2rem] p-8 shadow-2xl border-white/40 space-y-8">
        <div className="flex flex-col lg:flex-row justify-between items-start lg:items-center gap-6">
          <div className="flex items-center gap-4">
            <div className="w-16 h-16 bg-violet-600 rounded-3xl flex items-center justify-center text-white shadow-xl">
              <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z"></path></svg>
            </div>
            <div>
              <h2 className="text-2xl font-bold text-gray-900 tracking-tight">智能档案查询</h2>
              <p className="text-gray-500 text-xs font-bold uppercase tracking-widest mt-1">Pediatric Database Search</p>
            </div>
          </div>

          <div className="flex items-center bg-black/5 p-1 rounded-2xl border border-white/50">
             <button onClick={() => setShowInsights(false)} className={`px-6 py-2 rounded-xl text-sm font-bold transition-all ${!showInsights ? 'bg-white text-violet-600 shadow-md' : 'text-gray-500 hover:text-gray-900'}`}>列表</button>
             <button onClick={() => setShowInsights(true)} className={`px-6 py-2 rounded-xl text-sm font-bold transition-all ${showInsights ? 'bg-white text-violet-600 shadow-md' : 'text-gray-500 hover:text-gray-900'}`}>统计</button>
          </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-12 gap-4">
          <div className="relative group lg:col-span-6">
            <input type="text" placeholder="搜索姓名、药物、临床表现..." value={searchTerm} onChange={(e) => setSearchTerm(e.target.value)} className="w-full pl-12 pr-4 py-4 bg-white rounded-2xl border-0 ring-1 ring-black/5 focus:ring-4 focus:ring-violet-500/20 outline-none transition-all font-semibold" />
            <svg className="w-6 h-6 text-gray-400 absolute left-4 top-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z"></path></svg>
          </div>
          <div className="lg:col-span-4 flex gap-2">
             <input type="date" value={startDate} onChange={(e) => setStartDate(e.target.value)} className="flex-1 px-4 py-4 bg-white rounded-2xl border-0 ring-1 ring-black/5 font-semibold text-sm outline-none" />
             <input type="date" value={endDate} onChange={(e) => setEndDate(e.target.value)} className="flex-1 px-4 py-4 bg-white rounded-2xl border-0 ring-1 ring-black/5 font-semibold text-sm outline-none" />
          </div>
          <button onClick={() => {setSearchTerm(''); setStartDate(''); setEndDate('');}} className="lg:col-span-2 py-4 bg-gray-100 text-gray-600 rounded-2xl font-bold hover:bg-gray-200 transition">重置</button>
        </div>
      </div>

      {showInsights && stats ? (
        <div className="grid grid-cols-1 md:grid-cols-3 gap-8 animate-fade-in">
          <div className="glass rounded-[2rem] p-8 flex flex-col items-center justify-center space-y-6 shadow-xl border-white/40">
            <h3 className="text-sm font-black text-gray-400 uppercase tracking-widest">性别占比</h3>
            <div className="relative w-40 h-40">
               <svg className="w-full h-full transform -rotate-90"><circle cx="80" cy="80" r="70" fill="transparent" stroke="#F3F4F6" strokeWidth="16" /><circle cx="80" cy="80" r="70" fill="transparent" stroke="#8B5CF6" strokeWidth="16" strokeDasharray={440} strokeDashoffset={440 * (1 - stats.genderCount.male / stats.total)} /></svg>
               <div className="absolute inset-0 flex flex-col items-center justify-center">
                  <span className="text-3xl font-black text-gray-900">{Math.round((stats.genderCount.male / stats.total) * 100)}%</span>
                  <span className="text-xs text-gray-500">男童</span>
               </div>
            </div>
          </div>
          <div className="glass rounded-[2rem] p-8 space-y-6 shadow-xl border-white/40">
            <h3 className="text-sm font-black text-gray-400 uppercase tracking-widest">年龄分布</h3>
            <div className="space-y-4">
              {[
                { label: '婴儿(0-1)', count: stats.ageGroups.infant },
                { label: '幼儿(1-3)', count: stats.ageGroups.toddler },
                { label: '学龄前(3-6)', count: stats.ageGroups.preschool },
                { label: '学龄(6-12)', count: stats.ageGroups.school },
                { label: '青春(12-18+)', count: stats.ageGroups.adolescent },
              ].map((item, i) => (
                <div key={i} className="space-y-1">
                   <div className="flex justify-between text-xs font-bold"><span className="text-gray-500">{item.label}</span><span className="text-gray-900">{item.count}</span></div>
                   <div className="w-full h-2.5 bg-gray-100 rounded-full overflow-hidden"><div className="h-full bg-sky-400" style={{ width: `${(item.count / stats.total) * 100}%` }}></div></div>
                </div>
              ))}
            </div>
          </div>
          <div className="glass rounded-[2rem] p-8 space-y-6 shadow-xl border-white/40">
            <h3 className="text-sm font-black text-gray-400 uppercase tracking-widest">热门药物</h3>
            <div className="space-y-4">
               {stats.topMeds.map(([name, count], i) => (
                 <div key={i} className="flex items-center gap-4">
                    <div className="w-8 h-8 rounded-xl bg-violet-100 text-violet-600 flex items-center justify-center font-bold text-xs">{i+1}</div>
                    <div className="flex-1"><div className="flex justify-between items-center mb-1"><span className="text-xs font-bold text-gray-800">{name}</span><span className="text-[10px] text-gray-500">{count}例</span></div><div className="w-full h-1.5 bg-gray-100 rounded-full"><div className="h-full bg-fuchsia-400 rounded-full" style={{ width: `${(count / stats.total) * 100}%` }}></div></div></div>
                 </div>
               ))}
            </div>
          </div>
        </div>
      ) : (
        <div className="glass rounded-[2rem] overflow-hidden shadow-2xl border-white/40">
          <div className="overflow-x-auto">
            <table className="w-full text-left border-collapse">
              <thead>
                <tr className="bg-white/50 border-b border-white/30 text-xs font-black text-gray-400 uppercase tracking-widest uppercase">
                  <th className="px-6 py-5">#</th>
                  <th className="px-6 py-5">患儿基础信息</th>
                  <th className="px-6 py-5">当前诊断</th>
                  <th className="px-6 py-5">正在进行方案</th>
                  <th className="px-6 py-5 text-center">操作</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-white/20">
                {filteredPatients.map((p) => (
                  <tr key={p.id} className="hover:bg-white/40 transition-colors group">
                    <td className="px-6 py-6 text-gray-400 font-bold">{p.name[0]}</td>
                    <td className="px-6 py-6 cursor-pointer" onClick={() => onSelect(p)}>
                      <div className="font-bold text-gray-900">{p.name}</div>
                      <div className="text-xs text-gray-500 font-medium">{p.gender} · {p.age}岁</div>
                      <div className="mt-1 text-[9px] text-violet-500 font-black flex items-center gap-1">
                        <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"/></svg>
                        查看历史 ({p.visitHistory.length})
                      </div>
                    </td>
                    <td className="px-6 py-6">
                      <div className="flex flex-col gap-1">
                        <span className="px-2.5 py-1 bg-sky-50 text-sky-700 text-[10px] font-black rounded-lg inline-block border border-sky-100">{p.diagnosis}</span>
                      </div>
                    </td>
                    <td className="px-6 py-6">
                      <div className="flex flex-wrap gap-1.5 max-w-xs">
                        {p.medications.filter(m => !m.endDate).map((m, i) => (
                          <div key={i} className="px-2 py-1 bg-violet-50 text-violet-600 text-[9px] font-bold rounded-lg border border-violet-100">{m.name.split(' ')[0]}</div>
                        ))}
                      </div>
                    </td>
                    <td className="px-6 py-6 text-center">
                      <div className="flex items-center justify-center gap-2">
                        <button title="新诊录入" onClick={() => onNewVisit(p)} className="p-2.5 bg-sky-50 text-sky-600 rounded-xl hover:bg-sky-500 hover:text-white transition-all shadow-sm">
                          <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M12 4v16m8-8H4"></path></svg>
                        </button>
                        <button title="资料修改" onClick={() => onEdit(p)} className="p-2.5 bg-violet-50 text-violet-600 rounded-xl hover:bg-violet-600 hover:text-white transition-all shadow-sm">
                          <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z"></path></svg>
                        </button>
                        <button title="删除" onClick={() => onDelete(p.id)} className="p-2.5 bg-fuchsia-50 text-fuchsia-500 rounded-xl hover:bg-fuchsia-500 hover:text-white transition-all shadow-sm">
                          <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16"></path></svg>
                        </button>
                      </div>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}
    </div>
  );
};

export default PatientList;

import React, { useState, useEffect } from 'react';
import Dashboard from './components/Dashboard';
import PatientForm from './components/PatientForm';
import PatientList from './components/PatientList';
import PatientHistory from './components/PatientHistory';
import { storage } from './services/storage';
import { Patient } from './types';

enum View {
  DASHBOARD = 'DASHBOARD',
  LIST = 'LIST',
  FORM = 'FORM',
  HISTORY = 'HISTORY'
}

const App: React.FC = () => {
  const [activeView, setActiveView] = useState<View>(View.DASHBOARD);
  const [patients, setPatients] = useState<Patient[]>([]);
  const [editingPatient, setEditingPatient] = useState<Patient | undefined>(undefined);
  const [historyPatient, setHistoryPatient] = useState<Patient | undefined>(undefined);
  const [isNewVisitMode, setIsNewVisitMode] = useState<boolean>(false);

  useEffect(() => {
    setPatients(storage.getPatients());
  }, []);

  const handleSavePatient = (patient: Patient, isNewVisit: boolean) => {
    if (editingPatient) {
      storage.updatePatient(patient);
    } else {
      storage.addPatient(patient);
    }
    setPatients(storage.getPatients());
    setActiveView(View.DASHBOARD);
    setEditingPatient(undefined);
    setIsNewVisitMode(false);
  };

  const handleDeletePatient = (id: string) => {
    if (window.confirm('确认删除该病人记录？此操作无法撤销。')) {
      storage.deletePatient(id);
      setPatients(storage.getPatients());
    }
  };

  const handleDeleteMultiplePatients = (ids: string[]) => {
    if (window.confirm(`确定要永久删除选中的 ${ids.length} 名患者记录吗？`)) {
      const allPatients = storage.getPatients();
      const filtered = allPatients.filter(p => !ids.includes(p.id));
      storage.savePatients(filtered);
      setPatients(filtered);
    }
  };

  const handleEditPatient = (patient: Patient) => {
    setEditingPatient(patient);
    setIsNewVisitMode(false);
    setActiveView(View.FORM);
  };

  const handleNewVisit = (patient: Patient) => {
    setEditingPatient(patient);
    setIsNewVisitMode(true);
    setActiveView(View.FORM);
  };

  const handleViewHistory = (patient: Patient) => {
    setHistoryPatient(patient);
    setActiveView(View.HISTORY);
  };

  return (
    <div className="min-h-screen flex flex-col pb-20 md:pb-0">
      <header className="sticky top-0 z-50 glass border-b-0">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex justify-between h-20 items-center">
            <div className="flex items-center gap-3">
              <div className="w-12 h-12 bg-gradient-to-br from-violet-400 to-violet-600 rounded-2xl flex items-center justify-center text-white font-black italic shadow-lg">
                LZ
              </div>
              <h1 className="text-xl font-bold text-gray-900 tracking-tight hidden sm:block">LZRYEK 癫痫随访</h1>
            </div>

            <nav className="flex space-x-1.5 bg-black/5 p-1.5 rounded-2xl">
              {[
                { id: View.DASHBOARD, label: '概览', icon: 'M4 6h16M4 12h16M4 18h16' },
                { id: View.LIST, label: '查询', icon: 'M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z' },
                { id: View.FORM, label: '建档', icon: 'M12 4v16m8-8H4' },
              ].map(item => (
                <button
                  key={item.id}
                  onClick={() => {
                    setActiveView(item.id);
                    if (item.id !== View.FORM) {
                      setEditingPatient(undefined);
                      setIsNewVisitMode(false);
                    }
                  }}
                  className={`flex items-center gap-2 px-4 py-2 rounded-xl text-sm font-semibold transition-all duration-300 ${
                    (activeView === item.id || (activeView === View.HISTORY && item.id === View.LIST)) 
                    ? 'bg-white shadow-sm text-violet-600' 
                    : 'text-gray-500 hover:text-gray-900'
                  }`}
                >
                  <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d={item.icon}></path>
                  </svg>
                  <span className="hidden md:inline">{item.label}</span>
                </button>
              ))}
            </nav>
          </div>
        </div>
      </header>

      <main className="flex-1 max-w-7xl mx-auto w-full px-4 sm:px-6 lg:px-8 py-8">
        {activeView === View.DASHBOARD && (
          <Dashboard 
            patients={patients} 
            onSelectPatient={handleNewVisit} // Dashboard 点击提醒直接去录就诊
            onAddClick={() => {
              setEditingPatient(undefined);
              setIsNewVisitMode(false);
              setActiveView(View.FORM);
            }}
          />
        )}

        {activeView === View.LIST && (
          <PatientList 
            patients={patients} 
            onSelect={handleViewHistory} 
            onNewVisit={handleNewVisit}
            onEdit={handleEditPatient}
            onDelete={handleDeletePatient}
            onDeleteMultiple={handleDeleteMultiplePatients}
          />
        )}

        {activeView === View.FORM && (
          <PatientForm 
            initialData={editingPatient}
            isNewVisit={isNewVisitMode}
            onSubmit={handleSavePatient}
            onCancel={() => {
              setActiveView(View.DASHBOARD);
              setEditingPatient(undefined);
              setIsNewVisitMode(false);
            }}
          />
        )}

        {activeView === View.HISTORY && historyPatient && (
          <PatientHistory 
            patient={historyPatient}
            onBack={() => {
              setActiveView(View.LIST);
              setHistoryPatient(undefined);
            }}
          />
        )}
      </main>

      <footer className="mt-auto py-8 text-center text-gray-600 text-xs px-4">
        <p className="opacity-75">© 2024 LZRYEK Epilepsy Management. <i>By Jefflong</i></p>
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { Patient, Gender, Medication, VisitRecord } from '../types';
import { COMMON_MEDICATIONS, FOLLOW_UP_ITEMS } from '../constants';

interface PatientFormProps {
  initialData?: Patient;
  isNewVisit?: boolean;
  onSubmit: (data: Patient, isNewVisit: boolean) => void;
  onCancel: () => void;
}

const PatientForm: React.FC<PatientFormProps> = ({ initialData, isNewVisit = false, onSubmit, onCancel }) => {
  const [formData, setFormData] = useState<Partial<Patient>>({
    name: '', gender: Gender.MALE, birthday: '', age: 0, allergies: '', familyHistory: '', idCard: '', phone: '',
    clinicalSummary: { syndrome: '', seizureType: '', eeg: '', mri: '', genetic: '', biochemical: '', other: '' },
    diagnosis: '', diagnosisDate: new Date().toISOString().split('T')[0],
    medications: [{ name: '', usage: '', dosage: '', startDate: new Date().toISOString().split('T')[0], endDate: '' }],
    followUpConfig: { items: [], intervalMonths: 3, lastFollowUpDate: new Date().toISOString().split('T')[0], nextFollowUpDate: '' },
    visitHistory: []
  });

  const [otherFollowUpText, setOtherFollowUpText] = useState('');

  useEffect(() => { 
    if (initialData) {
      setFormData(initialData);
      const customItem = initialData.followUpConfig.items.find(item => !FOLLOW_UP_ITEMS.includes(item));
      if (customItem) setOtherFollowUpText(customItem);
    } 
  }, [initialData]);

  useEffect(() => {
    if (formData.birthday) {
      const birth = new Date(formData.birthday);
      const today = new Date();
      let age = today.getFullYear() - birth.getFullYear();
      const m = today.getMonth() - birth.getMonth();
      if (m < 0 || (m === 0 && today.getDate() < birth.getDate())) age--;
      setFormData(prev => ({ ...prev, age: Math.max(0, age) }));
    }
  }, [formData.birthday]);

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement | HTMLTextAreaElement>) => {
    const { name, value } = e.target;
    if (name.includes('.')) {
      const [parent, child] = name.split('.');
      setFormData(prev => ({ ...prev, [parent]: { ...(prev[parent as keyof Patient] as any), [child]: value } }));
    } else {
      setFormData(prev => ({ ...prev, [name]: value }));
    }
  };

  const handleMedicationChange = (index: number, field: keyof Medication, value: string) => {
    const newMeds = [...(formData.medications || [])];
    newMeds[index] = { ...newMeds[index], [field]: value };
    setFormData(prev => ({ ...prev, medications: newMeds }));
  };

  const calculateNextDate = () => {
    if (!formData.followUpConfig?.lastFollowUpDate || !formData.followUpConfig?.intervalMonths) return;
    const lastDate = new Date(formData.followUpConfig.lastFollowUpDate);
    lastDate.setMonth(lastDate.getMonth() + Number(formData.followUpConfig.intervalMonths));
    setFormData(prev => ({ ...prev, followUpConfig: { ...prev.followUpConfig!, nextFollowUpDate: lastDate.toISOString().split('T')[0] } }));
  };

  useEffect(() => { calculateNextDate(); }, [formData.followUpConfig?.lastFollowUpDate, formData.followUpConfig?.intervalMonths]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    let finalItems = [...(formData.followUpConfig?.items || [])].filter(i => i !== '其他');
    if (formData.followUpConfig?.items.includes('其他') && otherFollowUpText.trim()) finalItems.push(otherFollowUpText.trim());

    const currentFollowUpConfig = { ...formData.followUpConfig!, items: finalItems };
    let updatedHistory = [...(formData.visitHistory || [])];

    // 生成新的就诊记录快照
    if (!initialData || isNewVisit) {
      const newVisit: VisitRecord = {
        id: crypto.randomUUID(),
        date: formData.followUpConfig?.lastFollowUpDate || new Date().toISOString().split('T')[0],
        clinicalSummary: { ...formData.clinicalSummary! },
        medications: [...(formData.medications || [])],
        followUpConfig: { ...currentFollowUpConfig }
      };
      updatedHistory.push(newVisit);
    }

    onSubmit({ 
      ...(formData as Patient), 
      followUpConfig: currentFollowUpConfig, 
      visitHistory: updatedHistory,
      id: initialData?.id || crypto.randomUUID(), 
      createdAt: initialData?.createdAt || Date.now() 
    }, isNewVisit);
  };

  const toggleItem = (item: string) => {
    const items = formData.followUpConfig?.items || [];
    setFormData(prev => ({ ...prev, followUpConfig: { ...prev.followUpConfig!, items: items.includes(item) ? items.filter(i => i !== item) : [...items, item] } }));
  };

  return (
    <form onSubmit={handleSubmit} className="glass rounded-[2.5rem] p-8 space-y-10 animate-fade-in overflow-y-auto max-h-[85vh] shadow-2xl border-white/40">
      <div className="flex justify-between items-center pb-6 border-b border-white/30">
        <div>
           <h2 className="text-4xl font-black text-gray-900 tracking-tight">
             {isNewVisit ? '录入新诊记录' : (initialData ? '修改患儿基本资料' : '新建患儿诊疗档案')}
           </h2>
           <p className="text-violet-500 text-base font-black uppercase tracking-[0.2em] mt-1">
             {isNewVisit ? 'New Clinical Visit Record' : 'Patient Information Management'}
           </p>
        </div>
        <button type="button" onClick={onCancel} className="p-3 bg-black/5 hover:bg-black/10 rounded-full transition-colors">
          <svg className="w-8 h-8 text-gray-600" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M6 18L18 6M6 6l12 12"></path></svg>
        </button>
      </div>

      <div className="space-y-12">
        <section>
          <div className="flex items-center gap-2 mb-6 ml-1">
             <div className="w-2 h-8 bg-violet-500 rounded-full"></div>
             <h3 className="text-2xl font-bold">患儿基本信息 {isNewVisit && '(只读参考)'}</h3>
          </div>
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6 bg-white/40 p-8 rounded-[2rem] border border-white/50 shadow-inner">
            <div className="space-y-2">
              <label className="text-base font-black text-gray-400 uppercase tracking-widest px-1">患儿姓名</label>
              <input name="name" value={formData.name} onChange={handleInputChange} disabled={isNewVisit} className={`w-full px-5 py-4 bg-white rounded-2xl border-0 ring-1 ring-black/5 focus:ring-4 focus:ring-violet-500/20 outline-none transition-all font-semibold text-lg ${isNewVisit ? 'opacity-50' : ''}`} required />
            </div>
            <div className="space-y-2">
              <label className="text-base font-black text-gray-400 uppercase tracking-widest px-1">性别</label>
              <select name="gender" value={formData.gender} onChange={handleInputChange} disabled={isNewVisit} className={`w-full px-5 py-4 bg-white rounded-2xl border-0 ring-1 ring-black/5 outline-none font-semibold text-lg ${isNewVisit ? 'opacity-50' : ''}`}>
                <option value={Gender.MALE}>男</option>
                <option value={Gender.FEMALE}>女</option>
              </select>
            </div>
            <div className="space-y-2">
              <label className="text-base font-black text-sky-600 uppercase tracking-widest px-1">出生日期</label>
              <input type="date" name="birthday" value={formData.birthday} onChange={handleInputChange} disabled={isNewVisit} className={`w-full px-5 py-4 bg-white rounded-2xl border-0 ring-1 ring-black/5 outline-none font-semibold text-lg ${isNewVisit ? 'opacity-50' : ''}`} required />
            </div>
            <div className="space-y-2">
              <label className="text-base font-black text-gray-400 uppercase tracking-widest px-1">计算年龄</label>
              <div className="w-full px-5 py-4 bg-gray-100/50 text-gray-400 rounded-2xl border-0 ring-1 ring-black/5 font-bold text-lg">{formData.age} 岁</div>
            </div>
          </div>
        </section>

        <section>
          <div className="flex items-center gap-2 mb-6 ml-1">
             <div className="w-2 h-8 bg-fuchsia-500 rounded-full"></div>
             <h3 className="text-2xl font-bold">{isNewVisit ? '本次就诊用药方案' : '药物管理 (ASM)'}</h3>
          </div>
          <div className="space-y-6">
            {(formData.medications || []).map((med, idx) => (
              <div key={idx} className="bg-white/50 p-6 rounded-3xl border border-white/50 space-y-4 shadow-sm relative group transition-all hover:bg-white/70">
                <div className="grid grid-cols-1 lg:grid-cols-12 gap-4 items-end">
                  <div className="lg:col-span-3 space-y-2">
                    <label className="text-base font-black text-gray-400 uppercase tracking-widest ml-1">药物名称</label>
                    <select value={COMMON_MEDICATIONS.includes(med.name) ? med.name : (med.name === '' ? '' : 'OTHER')} onChange={(e) => handleMedicationChange(idx, 'name', e.target.value === 'OTHER' ? ' ' : e.target.value)} className="w-full px-4 py-3.5 bg-white rounded-xl outline-none text-lg font-bold border-0 ring-1 ring-black/5">
                      <option value="">选择药物...</option>
                      {COMMON_MEDICATIONS.map(m => <option key={m} value={m}>{m}</option>)}
                      <option value="OTHER">其他...</option>
                    </select>
                    {(!COMMON_MEDICATIONS.includes(med.name) && med.name !== '') && (
                      <input value={med.name === ' ' ? '' : med.name} onChange={(e) => handleMedicationChange(idx, 'name', e.target.value)} className="w-full px-4 py-3.5 mt-2 bg-violet-50 border-2 border-violet-200 rounded-xl outline-none text-lg font-black" placeholder="输入药名" />
                    )}
                  </div>
                  <div className="lg:col-span-2 space-y-2">
                    <label className="text-base font-black text-gray-400 uppercase tracking-widest ml-1">用法</label>
                    <input value={med.usage} onChange={(e) => handleMedicationChange(idx, 'usage', e.target.value)} className="w-full px-4 py-3.5 bg-white rounded-xl outline-none text-lg font-semibold border-0 ring-1 ring-black/5" placeholder="如: bid" />
                  </div>
                  <div className="lg:col-span-2 space-y-2">
                    <label className="text-base font-black text-gray-400 uppercase tracking-widest ml-1">用量</label>
                    <input value={med.dosage} onChange={(e) => handleMedicationChange(idx, 'dosage', e.target.value)} className="w-full px-4 py-3.5 bg-white rounded-xl outline-none text-lg font-semibold border-0 ring-1 ring-black/5" placeholder="如: 0.25g" />
                  </div>
                  <div className="lg:col-span-2 space-y-2">
                    <label className="text-base font-black text-violet-600 uppercase tracking-widest ml-1">起始日期</label>
                    <input type="date" value={med.startDate} onChange={(e) => handleMedicationChange(idx, 'startDate', e.target.value)} className="w-full px-4 py-3.5 bg-white rounded-xl outline-none text-lg font-semibold border-0 ring-1 ring-black/5" />
                  </div>
                  <div className="lg:col-span-2 space-y-2">
                    <label className="text-base font-black text-fuchsia-600 uppercase tracking-widest ml-1">停药时间</label>
